DAILY_METRIC_DEFAULTS = {
    "water_glasses": 0,
    "sleep_hours": None,
    "mood": None,
    "steps": None,
    "heart_rate_resting": None,
}

@_short_cache(ttl=1.5)
def get_daily_metrics(date_key=None):
    date_key = date_key or _today_key()
    if st.session_state.get("is_authenticated"):
        # Partner-view consent check for the vitals scope.
        if st.session_state.get("viewing_partner_hash"):
            if not viewer_can_see("vitals"):
                return {**DAILY_METRIC_DEFAULTS}
            _log_partner_view("vitals")
        all_dm = (get_user_doc() or {}).get("daily_metrics", {}) or {}
    else:
        all_dm = _ensure_guest_store()["daily_metrics"]
    # Merge with defaults so missing keys are explicit None rather than KeyError-prone.
    raw = all_dm.get(date_key, {})
    return {**DAILY_METRIC_DEFAULTS, **raw}


def get_all_daily_metrics():
    """Return the full daily_metrics map (dict keyed by ISO date) for the
    current user. One DB fetch, for callers that need history across many
    days (e.g. sparklines on the home page) instead of just one day."""
    if st.session_state.get("is_authenticated"):
        # Partner-view consent check for the vitals scope.
        if st.session_state.get("viewing_partner_hash"):
            if not viewer_can_see("vitals"):
                return {}
        return (get_user_doc() or {}).get("daily_metrics", {}) or {}
    return _ensure_guest_store()["daily_metrics"]


def get_metric_series(all_dm, metric_key, days=7):
    """Return numeric values for the last `days` days (oldest first),
    skipping any day where the metric has no value.

    Pure / side-effect-free: takes the daily_metrics dict as input so
    callers can fetch once and reuse across multiple metrics. Returns
    floats (raw values coerced if possible, skipped if not numeric).
    """
    if not isinstance(all_dm, dict):
        return []
    today = datetime.now().date()
    values = []
    for i in range(days - 1, -1, -1):
        d = (today - timedelta(days=i)).strftime("%Y-%m-%d")
        day = all_dm.get(d, {}) or {}
        v = day.get(metric_key)
        if v is None:
            continue
        try:
            values.append(float(v))
        except (TypeError, ValueError):
            continue
    return values


def render_sparkline_path(values, view_w=96, view_h=28, padding=2):
    """Build an SVG path 'd' attribute that plots `values` as a polyline
    across the given viewBox. Empty string if fewer than 2 values so the
    caller can show an honest empty state instead of a fake decorative
    curve.

    Normalization is per-metric (each call uses its own min/max), so a
    series of values like [60, 72, 65] renders the same visual amplitude
    as [8000, 12000, 9500], the shape encodes the *trend* faithfully.

    Y is inverted to match how charts read: higher values draw higher
    on the page. SVG natively has y=0 at top, so we flip the
    normalized value before placing.
    """
    if not values or len(values) < 2:
        return ""
    n = len(values)
    min_v = min(values)
    max_v = max(values)
    avail_w = view_w - 2 * padding
    avail_h = view_h - 2 * padding
    if max_v == min_v:
        # All values identical, draw a flat centerline so the user
        # sees "no change" rather than a misleading slope or empty SVG.
        y_mid = round(view_h / 2, 1)
        return ("M" + str(padding) + "," + str(y_mid) +
                " L" + str(view_w - padding) + "," + str(y_mid))
    points = []
    for i, v in enumerate(values):
        x = padding + (i / (n - 1)) * avail_w
        normalized = (v - min_v) / (max_v - min_v)
        y = view_h - padding - normalized * avail_h
        points.append((round(x, 1), round(y, 1)))
    path = "M" + str(points[0][0]) + "," + str(points[0][1])
    for x, y in points[1:]:
        path += " L" + str(x) + "," + str(y)
    return path

def heart_rate_status(bpm):
    """Return (label, css_status_class) for a resting heart rate, or (None, None).

    Clinical thresholds (resting, adult):
      < 50    : low (bradycardia, possible concern)
      50-59   : low-normal (athletic / borderline low)
      60-89   : normal
      90-99   : elevated (upper edge of normal, worth noticing)
      >= 100  : high (tachycardia, clinical attention if persistent)
    """
    if bpm is None:
        return (None, None)
    try:
        v = int(bpm)
    except Exception:
        return (None, None)
    if v < 50:
        return ("Low", "md-status-alert")
    if v < 60:
        return ("Low-normal", "md-status-info")
    if v < 90:
        return ("Normal", "md-status-good")
    if v < 100:
        return ("Elevated", "md-status-warn")
    return ("High", "md-status-alert")

def sleep_status(hours):
    """Adult sleep thresholds (NHS / AASM): 7-9h optimal, 6-7h or 9-10h fair,
    < 6h or > 10h flagged as inadequate / excess."""
    if hours is None:
        return (None, None)
    try:
        v = float(hours)
    except Exception:
        return (None, None)
    if 7 <= v <= 9:
        return ("Good", "md-status-good")
    if 6 <= v < 7 or 9 < v <= 10:
        return ("Fair", "md-status-info")
    if v < 5 or v > 11:
        return ("Low" if v < 6 else "High", "md-status-alert")
    return ("Low" if v < 6 else "High", "md-status-warn")

def daily_trend_warnings(today_metrics, yesterday_metrics):
    """Compare today vs yesterday for the four core vitals and return a list
    of short warning strings the UI can render as chips. Returns [] when
    everything looks unchanged or when yesterday's data is missing.

    Trigger thresholds (deliberately conservative so we don't alarm-fatigue):
      Heart rate : +/- 20 bpm jump, OR crossing the 100 / 60 threshold.
      Sleep      : drop of >= 2 hours, OR sleep < 5h while yesterday was normal.
      Steps      : drop of >= 5000 steps when yesterday was >= 4000.
      Water      : <= 2 glasses when yesterday was >= 6.
    """
    out = []
    if not today_metrics or not yesterday_metrics:
        return out

    def _i(x):
        try:
            return int(x)
        except Exception:
            return None
    def _f(x):
        try:
            return float(x)
        except Exception:
            return None

    hr_t = _i(today_metrics.get("heart_rate_resting"))
    hr_y = _i(yesterday_metrics.get("heart_rate_resting"))
    if hr_t is not None and hr_y is not None:
        diff = hr_t - hr_y
        if abs(diff) >= 20:
            direction = "up" if diff > 0 else "down"
            out.append("Heart rate jumped " + direction + " " + str(abs(diff)) + " bpm vs yesterday")
        elif hr_t >= 100 and hr_y < 100:
            out.append("Heart rate crossed into the high range today")
        elif hr_t < 60 and hr_y >= 60:
            out.append("Heart rate dropped below the normal range today")

    sl_t = _f(today_metrics.get("sleep_hours"))
    sl_y = _f(yesterday_metrics.get("sleep_hours"))
    if sl_t is not None and sl_y is not None:
        if sl_y - sl_t >= 2:
            out.append("Slept " + str(round(sl_y - sl_t, 1)) + "h less than yesterday")
        elif sl_t < 5 and sl_y >= 6:
            out.append("Very low sleep tonight, under 5 hours")

    st_t = _i(today_metrics.get("steps"))
    st_y = _i(yesterday_metrics.get("steps"))
    if st_t is not None and st_y is not None and st_y >= 4000 and (st_y - st_t) >= 5000:
        out.append("Activity dropped ~" + str(int((st_y - st_t) / 1000)) + "k steps vs yesterday")

    w_t = _i(today_metrics.get("water_glasses"))
    w_y = _i(yesterday_metrics.get("water_glasses"))
    if w_t is not None and w_y is not None and w_t <= 2 and w_y >= 6:
        out.append("Hydration is much lower today, only " + str(w_t) + " glass" + ("es" if w_t != 1 else ""))

    return out

def update_daily_metric(field, value, date_key=None):
    date_key = date_key or _today_key()
    if st.session_state.get("is_authenticated"):
        doc = get_user_doc() or {}
        all_dm = doc.get("daily_metrics", {}) or {}
        day = all_dm.get(date_key, {})
        day[field] = value
        all_dm[date_key] = day
        update_user_doc({"daily_metrics": all_dm})
    else:
        store = _ensure_guest_store()
        day = store["daily_metrics"].get(date_key, {})
        day[field] = value
        store["daily_metrics"][date_key] = day

def get_metrics_history(days=7):
    """Return list of (date_str, metrics_dict) for last N days."""
    if st.session_state.get("is_authenticated"):
        all_dm = (get_user_doc() or {}).get("daily_metrics", {}) or {}
    else:
        all_dm = _ensure_guest_store()["daily_metrics"]
    out = []
    for i in range(days - 1, -1, -1):
        d = (datetime.now() - timedelta(days=i)).strftime("%Y-%m-%d")
        out.append((d, {**DAILY_METRIC_DEFAULTS, **all_dm.get(d, {})}))
    return out

def log_query_to_firestore(query_data):
    """Write anonymised query metadata to Firestore. Silent failure if Firebase unavailable."""
    if not FIREBASE_ACTIVE:
        return
    try:
        safe_data = {
            "query_word_count": len(query_data.get("query", "").split()),
            "confidence": query_data.get("confidence", "unknown"),
            "confidence_pct": query_data.get("confidence_pct", 0),
            "sources": query_data.get("sources", []),
            "response_time": query_data.get("response_time", 0),
            "language": query_data.get("language", "English"),
            "mode": query_data.get("mode", "free_chat"),
            "emergency_triggered": query_data.get("emergency_triggered", False),
            "drug_alerts": query_data.get("drug_alerts", 0),
            "timestamp": firestore.SERVER_TIMESTAMP,
        }
        firestore_db.collection("medichat_queries").add(safe_data)
    except Exception as e:
        print("Firestore write failed:", e)

def fetch_all_queries_from_firestore(limit=500):
    """Retrieve all anonymised query logs for admin dashboard."""
    if not FIREBASE_ACTIVE:
        return []
    try:
        docs = firestore_db.collection("medichat_queries").order_by("timestamp", direction=firestore.Query.DESCENDING).limit(limit).stream()
        return [doc.to_dict() for doc in docs]
    except Exception as e:
        print("Firestore read failed:", e)
        return []

def ui_escape(value):
    """Escape dynamic text before placing it inside custom HTML."""
    return html.escape(str(value or ""), quote=True)

def ui_text(value, max_chars=None):
    text = re.sub(r"\s+", " ", str(value or "").strip())
    if max_chars and len(text) > max_chars:
        text = text[:max_chars - 3].rstrip() + "..."
    return ui_escape(text)

def ui_lines(value):
    return ui_escape(value).replace("\n", "<br>")

def get_user_local_now():
    tz_name = ""
    try:
        tz_name = getattr(st.context, "timezone", "") or ""
    except Exception:
        tz_name = ""
    if tz_name and ZoneInfo is not None:
        try:
            return datetime.now(ZoneInfo(tz_name))
        except Exception:
            pass
    return datetime.now()

def _msg_now_ts():
    """Return the current user-local time as a short '10:21 AM' string,
    used as a per-message timestamp for new conversations going forward.
    Old messages stored without a ts will simply skip the timestamp line."""
    try:
        return get_user_local_now().strftime("%-I:%M %p")
    except Exception:
        try:
            return get_user_local_now().strftime("%I:%M %p").lstrip("0")
        except Exception:
            return ""

def reset_prescription_reader_state():
    st.session_state.rx_reader_result = None
    st.session_state.rx_reader_saved_id = None
    st.session_state.rx_uploader_key = st.session_state.get("rx_uploader_key", 0) + 1

def start_new_chat_session():
    st.session_state.current_conversation_id = ""
    st.session_state.messages = []
    st.session_state.qcount = 0
    st.session_state.feedback = {}
    st.session_state.last_sources = []
    st.session_state.last_pdf_context = ""
    st.session_state.last_image_context = ""
    st.session_state.emergency_detected = False
    st.session_state.triage_assessment = None
    st.session_state.pending_user_input = ""
    st.session_state.chat_input_key = st.session_state.get("chat_input_key", 0) + 1
    st.session_state.uploader_key = st.session_state.get("uploader_key", 0) + 1
    st.session_state.home_show_vision_upload = False
    st.session_state.home_show_voice = False
    st.session_state.voice_audio_key = st.session_state.get("voice_audio_key", 0) + 1
    st.session_state.assessment_stage = 0
    st.session_state.assessment_data = {}
    st.session_state.assessment_complete = False
    st.session_state.assessment_report = None
    st.session_state.assessment_parsed = None
    st.session_state.mode = "chat"
    reset_prescription_reader_state()

