def load_known_drugs():
    csv_path = _safe_secret("AU_DRUGS_CSV_PATH", os.environ.get("AU_DRUGS_CSV_PATH", ""))
    known = set(AU_TOP_DRUGS_FALLBACK)
    if not csv_path:
        return known
    try:
        with open(csv_path, "r", encoding="utf-8") as f:
            for line in f:
                token = (line or "").strip().lower()
                if token and token not in {"drug", "name", "medication"}:
                    known.add(token)
    except Exception as e:
        print("Known-drug list load failed:", e)
    return known

KNOWN_DRUGS = load_known_drugs()

PRESCRIPTION_PROMPT = """You are a precise clinical transcription assistant trained on doctor handwriting, Australian + UK + US + South Asian (Indian, Sri Lankan, Bangladeshi) prescription formats, and standard medical Latin abbreviations. Your only job is to read the prescription image and transcribe what is written, faithfully and conservatively.
You are NOT giving medical advice, NOT diagnosing, and NOT prescribing treatment.

CRITICAL: This is the patient's OWN prescription that they uploaded for their own reference, not a third party document. You MUST attempt a transcription. Do NOT refuse with phrases like "I'm sorry, I can't assist with that", "I cannot help with this", "I am unable to read", or any similar safety apology, those refusals do not apply to a patient transcribing their own script. Even if the handwriting is very difficult, transcribe what you can read, mark unclear sections as "unclear" in the relevant field, and set the overall confidence to "low". Never return an apology with no transcription.

READING PROTOCOL:
1. Scan the prescriber/clinic header first to fix the document type.
2. Identify the patient identifiers.
3. Locate every medication line, including any inhaler or topical strip in the corner.
4. For each medication, extract: drug name, strength/dose, frequency, route, quantity, repeats.
5. Read the date and prescriber signature.

TRANSCRIPTION RULES:
- If a letter looks like a 'curl' (e.g. 'a/o', 't/l', '1/7'), pick the option that forms a real word or a real medication name. NEVER invent a drug.
- Expand standard Latin / medical abbreviations to plain English in the "Plain English" line:
  - bd / b.d.s = twice daily; tds / t.d.s = three times daily; qds / q.i.d = four times daily.
  - mane = morning; nocte = at night; prn = as needed; ac = before meals; pc = after meals.
  - po = by mouth; sl = sublingual; pr = rectal; sc = subcutaneous; im = intramuscular; iv = intravenous.
  - Mitte / Disp = quantity to dispense; rpts / repeats = repeats; stat = immediately.
- Brand vs generic: if both are written (e.g. "Panadol (paracetamol) 500 mg"), record the brand in Reading and add "(generic: paracetamol)" inline.
- Normalise common Australian PBS brands: Foracort (budesonide+formoterol), Ventolin (salbutamol), Symbicort (budesonide+formoterol), Seretide (fluticasone+salmeterol), Augmentin (amoxicillin+clavulanate), Panadol (paracetamol), Nurofen (ibuprofen), Endone (oxycodone), Targin (oxycodone+naloxone), Lyrica (pregabalin), Pristiq (desvenlafaxine).
- Strengths: always include the unit (mg, mcg, g, mL, IU). If the unit is missing on the script, write the number then "(unit unclear)".
- Frequency: if the script says "1 tab BD x 7/7", expand to "1 tablet, twice daily, for 7 days".
- If a section is unreadable, write "unclear", do not guess.

CONFIDENCE RULES:
- high: legible, unambiguous, drug matches a known medication.
- medium: legible but uncommon drug, or ambiguous handwriting that you resolved using context.
- low: significant guessing or unfamiliar drug; flag the affected section in ILLEGIBLE SECTIONS.

CRITICAL: A single prescription almost always contains MULTIPLE medications. Read the ENTIRE page top to bottom and transcribe EVERY medication, advice item, ointment, gel, inhaler, or prescribed product, even if it is in the bottom corner or written as "Adv:" (advice). Do NOT stop at the first medication.

For each medication, output a **MEDICATION #n** block with the structure below. Include as many blocks as there are medications on the script. Use the "after meals" / "before meals" / "with food" annotations from the brace { groupings if present, and apply them to every drug inside that brace.

Output this exact format (do NOT add extra sections or commentary):

**PATIENT**
Name: <as written on the script, or "not specified" if no patient name appears>
Age / Sex: <e.g. "28/M" if written, or "not specified">

**MEDICATION #1**
Reading: <best transcription, brand (generic) if both written>
Matches known drug: <yes/no>
Strength: <exact text including unit (mg, mcg, mL, IU), or "unclear">
As written: <exact text including abbreviations like 1-0-1 x 5 days, BD, TDS, PRN, mane, nocte>
Plain English: <expanded short rewrite, e.g. "1 tablet in the morning and 1 tablet at night, for 5 days, after meals">
Route: <oral / topical / inhaled / sublingual / subcutaneous / intramuscular / intravenous / rectal / not specified>
Quantity: <exact text or "not specified">
Refills: <exact text or "no repeats">
Confidence: high | medium | low

**MEDICATION #2**
(same fields as above)

(continue **MEDICATION #3**, **MEDICATION #4**, etc. for every medication on the script)

**PRESCRIBER**
Name: <as written or unclear>
Clinic / Header: <e.g. "The White Tusk Dental" if written, or blank>
Date: <as written, normalised to DD/MM/YYYY if possible, or unclear>

**OVERALL CONFIDENCE**: high | medium | low
**ILLEGIBLE SECTIONS**: <list regions that are genuinely unreadable, or "none">
"""

def preprocess_prescription(image_bytes):
    """Boost contrast + sharpness + autocontrast at high resolution so the
    handwriting reads cleanly to the vision model. 2048px keeps fine
    pen-stroke detail without bloating the payload."""
    img = Image.open(io.BytesIO(image_bytes))
    img = ImageOps.exif_transpose(img)
    if img.mode != "RGB":
        img = img.convert("RGB")
    max_dim = 2048
    if max(img.size) > max_dim:
        img.thumbnail((max_dim, max_dim), Image.LANCZOS)
    # Autocontrast normalises lighting (phone photos often have heavy
    # shadows from the camera hand), then a measured contrast + sharpness
    # boost lifts the ink off the page.
    img = ImageOps.autocontrast(img, cutoff=1)
    img = ImageEnhance.Contrast(img).enhance(1.5)
    img = ImageEnhance.Sharpness(img).enhance(1.6)
    out = io.BytesIO()
    img.save(out, format="JPEG", quality=95)
    return out.getvalue()

def validate_drug_name(reading):
    candidate = (reading or "").lower().strip()
    if not candidate:
        return {"match": "none"}
    if candidate in KNOWN_DRUGS:
        return {"match": "exact", "drug": candidate}
    close = difflib.get_close_matches(candidate, KNOWN_DRUGS, n=3, cutoff=0.76)
    if close:
        return {"match": "close", "candidates": close}
    return {"match": "none"}

def extract_medication_reading(transcribed_text):
    m = re.search(r"\*\*MEDICATION\*\*.*?Reading:\s*(.+)", transcribed_text or "", flags=re.IGNORECASE | re.DOTALL)
    if not m:
        return ""
    line = (m.group(1) or "").splitlines()[0]
    return line.strip()[:120]

def read_prescription(image_bytes, user_note="", lang_instruction=""):
    processed = preprocess_prescription(image_bytes)
    b64 = base64.standard_b64encode(processed).decode("utf-8")
    prompt = PRESCRIPTION_PROMPT + ("\n\n" + lang_instruction if lang_instruction else "")
    if user_note and user_note.strip():
        prompt += "\n\nContext note from user: " + user_note.strip()[:200]

    reading = ""
    model_used = "unavailable"

    # Refusal-pattern detector. OpenAI's safety filter sometimes wrongly
    # apologises on handwritten scripts ("I'm sorry, I can't assist...").
    # When we see one, we treat it as no-reading and fall through to Claude.
    def _is_rx_refusal(text):
        if not text:
            return True
        t = text.lower().strip()
        if len(t) > 600:
            return False
        return any(p in t for p in (
            "i'm sorry, i can't",
            "i'm sorry, i cannot",
            "i am sorry, i can",
            "i can't assist with that",
            "i cannot assist with that",
            "i can't help with that",
            "i cannot help with that",
            "i'm unable to read",
            "i am unable to read",
            "i can't identify or analyze",
            "cannot identify or analyze",
        )) and "**MEDICATION" not in text.upper()

    # Prescription Reader dispatch order: OpenAI -> Claude -> Groq.
    if OPENAI_ACTIVE and openai_client is not None:
        try:
            resp = openai_client.chat.completions.create(
                model="gpt-4o",
                messages=[{
                    "role": "user",
                    "content": [
                        {"type": "text", "text": prompt},
                        {"type": "image_url", "image_url": {"url": "data:image/jpeg;base64," + b64, "detail": "high"}},
                    ],
                }],
                temperature=0.1,
                max_tokens=2000,
            )
            _openai_reading = resp.choices[0].message.content
            if _is_rx_refusal(_openai_reading):
                print("Prescription reader OpenAI returned a refusal, falling back to Claude.")
            else:
                reading = _openai_reading
                model_used = "openai-vision"
        except Exception as e:
            print("Prescription reader OpenAI pass failed, trying Claude:", e)

    if not reading and CLAUDE_ACTIVE:
        try:
            first = anthropic_client.messages.create(
                model=CLAUDE_MODEL,
                max_tokens=1600,
                messages=[{
                    "role": "user",
                    "content": [
                        {"type": "image", "source": {"type": "base64", "media_type": "image/jpeg", "data": b64}},
                        {"type": "text", "text": prompt},
                    ],
                }],
                temperature=0.2,
            )
            _claude_reading = first.content[0].text
            if _is_rx_refusal(_claude_reading):
                print("Prescription reader Claude returned a refusal, falling back to Groq.")
            else:
                reading = _claude_reading
                model_used = CLAUDE_MODEL
        except Exception as e:
            print("Prescription reader Claude pass failed:", e)

    if not reading and GROQ_ACTIVE and groq_client is not None:
        try:
            r = groq_client.chat.completions.create(
                model="meta-llama/llama-4-scout-17b-16e-instruct",
                messages=[{
                    "role": "user",
                    "content": [
                        {"type": "text", "text": prompt},
                        {"type": "image_url", "image_url": {"url": "data:image/jpeg;base64," + b64}},
                    ],
                }],
                temperature=0.2,
                max_tokens=1800,
            )
            _groq_reading = r.choices[0].message.content
            if _is_rx_refusal(_groq_reading):
                print("Prescription reader Groq returned a refusal too.")
                # All three providers refused. Return a clearer message
                # so the UI doesn't show a bare apology with no fields.
                return {"reading": "I had trouble reading this prescription. Please try a clearer, well-lit photo with the script flat and in focus.", "model_used": "all-refused", "overall_confidence": "low"}
            reading = _groq_reading
            model_used = "groq-vision"
        except Exception as e:
            print("Prescription reader Groq pass failed:", e)
            return {"reading": "I could not process this prescription image right now. Please try again with a clearer photo.", "model_used": "error", "overall_confidence": "low"}

    # Final safety net: if all providers ran but every reading was a refusal,
    # turn it into a clearer "try a clearer photo" message instead of leaking
    # the AI's apology to the user.
    if _is_rx_refusal(reading):
        return {"reading": "I had trouble reading this prescription. Please try a clearer, well-lit photo with the script flat and in focus.", "model_used": "all-refused", "overall_confidence": "low"}

    # Hallucination guard: when the script is genuinely illegible, the
    # anti-refusal prompt pushes the model to invent garbage names like
    # "All-on-4", "Oley Bowling AP", "Nid-of". Detect this by counting
    # parsed medications where the name doesn't match any known drug AND
    # confidence is low. If the whole script is in that state, return a
    # clean "couldn't read" message instead of the garbage cards.
    try:
        _hallu_parsed = parse_prescription_reading(reading)
        _hallu_meds = _hallu_parsed.get("medications") or []
        if _hallu_meds:
            _hallu_bad = 0
            for _hm in _hallu_meds:
                _match = (_hm.get("match") or "").strip().lower()
                _conf = (_hm.get("confidence") or "").strip().lower()
                _name = (_hm.get("name") or "").lower()
                _name_check = re.sub(r"[^a-z]", "", _name.split("(")[0])[:20]
                _known_hit = _name_check and _name_check in KNOWN_DRUGS
                if (_match != "yes" and _conf == "low" and not _known_hit):
                    _hallu_bad += 1
            if _hallu_bad == len(_hallu_meds):
                return {"reading": "I could not read this prescription clearly enough to transcribe it. The handwriting is too unclear for a reliable reading. Please retake the photo, well-lit, flat, in focus, and try again.", "model_used": model_used + "-illegible", "overall_confidence": "low"}
    except Exception:
        pass

    low_conf = "overall confidence**: low" in reading.lower() or "overall confidence: low" in reading.lower()
    if low_conf and CLAUDE_ACTIVE:
        try:
            second = anthropic_client.messages.create(
                model=os.environ.get("CLAUDE_RX_ESCALATION_MODEL", "claude-opus-4-7"),
                max_tokens=2200,
                messages=[{
                    "role": "user",
                    "content": [
                        {"type": "image", "source": {"type": "base64", "media_type": "image/jpeg", "data": b64}},
                        {"type": "text", "text": prompt + "\n\nA prior pass was low confidence. Re-check carefully using common Australian prescriptions."},
                    ],
                }],
                temperature=0.2,
            )
            reading = second.content[0].text
            model_used = os.environ.get("CLAUDE_RX_ESCALATION_MODEL", "claude-opus-4-7")
        except Exception as e:
            print("Prescription reader escalation failed:", e)

    med_reading = extract_medication_reading(reading)
    validation = validate_drug_name(med_reading)
    if validation.get("match") == "close":
        reading += "\n\n**Drug name check:** Closest known AU medications: " + ", ".join(validation.get("candidates", []))
    elif validation.get("match") == "exact":
        reading += "\n\n**Drug name check:** Exact match to known AU medication: " + validation.get("drug", "")

    overall = "medium"
    overall_match = re.search(r"\*\*OVERALL CONFIDENCE\*\*\s*:\s*(high|medium|low)", reading, flags=re.IGNORECASE)
    if overall_match:
        overall = overall_match.group(1).lower()

    parsed = parse_prescription_reading(reading)
    return {
        "reading": reading,
        "model_used": model_used,
        "overall_confidence": overall,
        "drug_validation": validation,
        "parsed": parsed,
        "patient_name": parsed.get("patient_name", ""),
    }

def parse_prescription_reading(text):
    """Break the structured **SECTION** transcription into a dict the UI can
    render as a clean, aligned prescription card. Now supports MULTIPLE
    **MEDICATION #n** blocks. The first medication's fields are flattened
    onto the top-level dict for backward compatibility; the full list lives
    under out['medications']. Missing sections degrade gracefully to empty
    strings, the renderer hides empty rows.
    """
    out = {
        "patient_name": "", "patient_age_sex": "",
        "medication": "", "medication_match": "", "medication_conf": "",
        "strength": "", "strength_conf": "",
        "frequency": "", "frequency_plain": "", "frequency_conf": "",
        "route": "",
        "quantity": "",
        "refills": "",
        "prescriber_name": "", "prescriber_clinic": "", "prescriber_date": "",
        "illegible": "",
        "drug_check": "",
        "medications": [],
    }
    if not text:
        return out

    def _grab(pattern, src=None, default=""):
        m = re.search(pattern, src if src is not None else text, flags=re.IGNORECASE | re.DOTALL)
        if not m:
            return default
        return (m.group(1) or "").strip().splitlines()[0].strip()

    out["patient_name"]      = _grab(r"\*\*PATIENT\*\*[\s\S]*?Name:\s*([^\n]+)")
    out["patient_age_sex"]   = _grab(r"\*\*PATIENT\*\*[\s\S]*?Age\s*/\s*Sex:\s*([^\n]+)")
    out["prescriber_name"]   = _grab(r"\*\*PRESCRIBER\*\*[\s\S]*?Name:\s*([^\n]+)")
    out["prescriber_clinic"] = _grab(r"\*\*PRESCRIBER\*\*[\s\S]*?Clinic\s*/\s*Header:\s*([^\n]+)")
    out["prescriber_date"]   = _grab(r"\*\*PRESCRIBER\*\*[\s\S]*?Date:\s*([^\n]+)")
    out["illegible"]         = _grab(r"\*\*ILLEGIBLE SECTIONS\*\*\s*:\s*([^\n]+)")
    out["drug_check"]        = _grab(r"\*\*Drug name check:\*\*\s*([^\n]+)")

    # Multi-medication blocks: split on "**MEDICATION #N**" markers.
    # Each block ends at the next **MEDICATION #** or the next top-level
    # **HEADER**. Handles both new "#N" format and legacy single "MEDICATION".
    med_blocks = re.findall(
        r"\*\*MEDICATION(?:\s*#\s*\d+)?\*\*([\s\S]*?)(?=\n\s*\*\*(?:MEDICATION(?:\s*#\s*\d+)?|PRESCRIBER|OVERALL|ILLEGIBLE|Drug name check)\*\*|\Z)",
        text, flags=re.IGNORECASE,
    )
    for block in med_blocks:
        med = {
            "name": _grab(r"Reading:\s*([^\n]+)", block),
            "match": _grab(r"Matches known drug:\s*([^\n]+)", block),
            "strength": _grab(r"Strength:\s*([^\n]+)", block),
            "frequency_raw": _grab(r"As written:\s*([^\n]+)", block),
            "frequency_plain": _grab(r"Plain English:\s*([^\n]+)", block),
            "route": _grab(r"Route:\s*([^\n]+)", block),
            "quantity": _grab(r"Quantity:\s*([^\n]+)", block),
            "refills": _grab(r"Refills:\s*([^\n]+)", block),
            "confidence": _grab(r"Confidence:\s*(high|medium|low)", block),
        }
        # Clean placeholder values so empty rows hide cleanly in the UI.
        for k, v in list(med.items()):
            vl = (v or "").strip().lower()
            if vl in {"not specified", "unclear", "none", "n/a", "na", "-", ",", "no repeats"}:
                med[k] = "" if k != "refills" else v  # keep "no repeats" as content
        # Skip blocks with no usable drug name at all.
        if med["name"]:
            out["medications"].append(med)

    # Backward compat: flatten the first medication onto the top-level keys
    # so legacy code paths (e.g. add_to_medications) still work.
    if out["medications"]:
        first = out["medications"][0]
        out["medication"]       = first["name"]
        out["medication_match"] = first["match"]
        out["medication_conf"]  = first["confidence"]
        out["strength"]         = first["strength"]
        out["strength_conf"]    = first["confidence"]
        out["frequency"]        = first["frequency_raw"]
        out["frequency_plain"]  = first["frequency_plain"]
        out["frequency_conf"]   = first["confidence"]
        out["route"]            = first["route"]
        out["quantity"]         = first["quantity"]
        out["refills"]          = first["refills"]

    # Clean top-level placeholders too
    for k in ("patient_name", "patient_age_sex", "prescriber_name", "prescriber_clinic", "prescriber_date", "illegible", "drug_check"):
        vl = (out.get(k) or "").strip().lower()
        if vl in {"not specified", "unclear", "none", "n/a", "na", "-", ","}:
            out[k] = ""
    return out

def looks_like_prescription_request(text):
    t = (text or "").lower()
    if not t:
        return False
    keys = [
        "prescription", "script", "handwriting", "doctor wrote", "doctor writing",
        "medicine name", "medication name", "can you read this", "what does this say",
        "dose on script", "rx", "chemist",
    ]
    return any(k in t for k in keys)

def encode_image(f):
    img = Image.open(f)
    if img.mode != "RGB":
        img = img.convert("RGB")
    buf = io.BytesIO()
    img.save(buf, format="JPEG")
    return base64.b64encode(buf.getvalue()).decode("utf-8")

def extract_pdf_text(uploaded_file):
    try:
        from pypdf import PdfReader
    except ImportError:
        try:
            from PyPDF2 import PdfReader
        except ImportError:
            return ""
    try:
        uploaded_file.seek(0)
        reader = PdfReader(uploaded_file)
        text_parts = []
        for page in reader.pages[:20]:
            try:
                text_parts.append(page.extract_text() or "")
            except Exception:
                continue
        full_text = "\n".join(text_parts).strip()
        if len(full_text) > 8000:
            full_text = full_text[:8000] + "\n\n[Document truncated for length]"
        return full_text
    except Exception as e:
        print("PDF extraction failed:", e)
        return ""

def medichat_pdf_analysis(question, pdf_text, all_messages, lang_instruction=""):
    memory = extract_patient_memory(all_messages)
    memory_context = build_memory_context(memory)

    system = (
        "You are MediChat, a warm and clinically competent AI health companion. "
        "A patient has uploaded a medical PDF report (likely a blood test, lab result, or clinical letter). "
        "Your job is to read the report, identify any abnormal values, explain what they mean in plain language, "
        "and highlight what the patient should pay attention to.\n\n"
        "RULES:\n"
        "- Never use em-dashes or en-dashes. Use commas, semicolons, or periods.\n"
        "- Be warm, conversational, and clear. Avoid jargon. Explain medical terms in plain words.\n"
        "- Highlight ABNORMAL values clearly first, then briefly summarise normal results.\n"
        "- If everything is normal, say so positively.\n"
        "- Suggest specific, actionable next steps based on what's abnormal.\n"
        "- Do not provide a final diagnosis. Use probability language and recommend clinician confirmation.\n"
        "- Do not prescribe medicines, initiate treatment plans, or provide exact dosing changes.\n"
        "- Mention patient by name if known, sparingly.\n"
        "- One brief disclaimer at most. The app shows a permanent disclaimer.\n\n"
        "FORMATTING RULES (CRITICAL for readability):\n"
        "- DO NOT use markdown headings (no #, ##, ###). They render badly in chat bubbles.\n"
        "- For section labels, write a short bold line like **What stands out:** on its own line, then continue on a new line.\n"
        "- Always put a blank line between sections.\n"
        "- Use **bold** sparingly for key values, drug names, or label headers.\n"
        "- Use bullet points (- item) for lists, each on its own line.\n"
        "- Keep paragraphs short, 2-3 sentences max.\n\n"
    )
    if lang_instruction:
        system += lang_instruction + "\n\n"
    # Saved profile data (medications, conditions, past records) gives the
    # PDF reviewer context like "this patient is on metformin so a 6.2% HbA1c
    # reads differently than for someone with no diabetes meds".
    profile_context = build_user_profile_context()
    if profile_context:
        system += (
            "PATIENT'S SAVED MEDICHAT PROFILE (authoritative, reference when relevant "
            "to interpreting the report below):\n" + profile_context + "\n\n"
        )
    if memory_context:
        system += "What this patient has told you in conversation:\n" + memory_context + "\n\n"

    system += "PATIENT'S UPLOADED REPORT:\n" + pdf_text + "\n\n"
    system += "PATIENT'S QUESTION ABOUT THE REPORT:\n" + (question or "Please review this report and tell me what stands out.")

    # PDF analysis dispatch order: OpenAI -> Claude -> Groq.
    _q_text = question or "Please review this report and tell me what stands out."

    if OPENAI_ACTIVE and openai_client is not None:
        try:
            resp = openai_client.chat.completions.create(
                model="gpt-4o-mini",
                messages=[
                    {"role": "system", "content": system},
                    {"role": "user", "content": _q_text},
                ],
                temperature=0.4,
                max_tokens=1500,
            )
            return resp.choices[0].message.content, "openai"
        except Exception as e:
            print("OpenAI PDF analysis failed, trying Claude:", e)

    if CLAUDE_ACTIVE:
        try:
            resp = anthropic_client.messages.create(
                model=CLAUDE_MODEL,
                max_tokens=1500,
                system=system,
                messages=[{"role": "user", "content": _q_text}],
                temperature=0.4,
            )
            return resp.content[0].text, "claude"
        except Exception as e:
            print("Claude PDF analysis failed, trying Groq:", e)

    if GROQ_ACTIVE and groq_client is not None:
        msgs = [{"role": "system", "content": system}, {"role": "user", "content": _q_text}]
        try:
            r = groq_client.chat.completions.create(
                model="llama-3.3-70b-versatile",
                messages=msgs,
                temperature=0.4,
                max_tokens=1500,
            )
            return r.choices[0].message.content, "groq"
        except Exception as e:
            print("Groq PDF analysis failed:", e)

    return ("PDF analysis is not available right now. Please configure an OpenAI, "
            "Anthropic, or Groq API key in Streamlit secrets."), "unavailable"

def extract_patient_memory(messages):
    memory = {"symptoms": [], "conditions": [], "medications": []}
    symptom_phrases = ["i have","i feel","i am feeling","i've been feeling","i'm experiencing","i suffer from","my back hurts","my chest","my stomach","i feel pain","feeling dizzy","feeling nauseous","i have a fever","i have a cough","i have a headache","shortness of breath","i've been tired","i feel tired","i have pain","i feel sick"]
    condition_phrases = ["i have diabetes","i have hypertension","i have asthma","i have cancer","i am diabetic","i am hypertensive","i was diagnosed with","i have high blood pressure","i have low blood pressure","i have depression","i have anxiety","i have heart","i have kidney"]
    medication_phrases = ["i am taking","i take","i was prescribed","i'm on","taking medication","prescribed me","i have an inhaler","i take tablets","i take pills"]
    for msg in messages:
        if msg.get("role") == "user" and msg.get("type") == "text":
            content = msg["content"].lower()
            for phrase in symptom_phrases:
                if phrase in content:
                    pos = content.find(phrase)
                    snippet = content[pos:pos+60].strip()
                    if snippet and snippet not in memory["symptoms"]:
                        memory["symptoms"].append(snippet)
                    break
            for phrase in condition_phrases:
                if phrase in content:
                    pos = content.find(phrase)
                    snippet = content[pos:pos+60].strip()
                    if snippet and snippet not in memory["conditions"]:
                        memory["conditions"].append(snippet)
                    break
            for phrase in medication_phrases:
                if phrase in content:
                    pos = content.find(phrase)
                    snippet = content[pos:pos+60].strip()
                    if snippet and snippet not in memory["medications"]:
                        memory["medications"].append(snippet)
                    break
    return memory

def build_memory_context(memory):
    parts = []
    if memory["symptoms"]:
        parts.append("Reported symptoms: " + ", ".join(memory["symptoms"]))
    if memory["conditions"]:
        parts.append("Mentioned conditions: " + ", ".join(memory["conditions"]))
    if memory["medications"]:
        parts.append("Referenced medications: " + ", ".join(memory["medications"]))
    return "\n".join(parts)


def build_user_profile_context():
    """Build a structured context block of the patient's explicitly-saved
    profile data, medications, appointments, uploaded health records and
    their summaries, plus today's vitals. This is the missing piece that
    lets the assistant give personalised answers grounded in what the user
    actually saved, rather than asking them to re-state everything.

    All four sources (medications, appointments, health records, daily
    metrics) work for both authenticated AND guest users, the underlying
    list_* helpers transparently swap between Firebase (signed-in) and the
    in-session guest store.

    Returns an empty string if the patient has not saved anything yet, callers should check before injecting into a system prompt so we don't
    waste tokens on a blank block.
    """
    parts = []

    # MEDICATIONS, most frequently referenced. Sort newest first so the
    # most recent additions appear at the top.
    try:
        meds = list_medications() or []
    except Exception:
        meds = []
    if meds:
        lines = [
            "MEDICATIONS ON FILE (this patient has explicitly saved these to "
            "their MediChat profile, treat as authoritative):"
        ]
        for m in meds[:25]:
            head = (m.get("name") or "(unnamed)").strip()
            spec_bits = []
            if m.get("dose"):
                spec_bits.append(str(m["dose"]).strip())
            if m.get("frequency"):
                spec_bits.append(str(m["frequency"]).strip())
            if m.get("time_of_day"):
                spec_bits.append(str(m["time_of_day"]).strip())
            spec = " · ".join([b for b in spec_bits if b])
            line = "  - " + head
            if spec:
                line += " (" + spec + ")"
            notes = (m.get("notes") or "").strip()
            if notes:
                line += ", Note: " + notes[:200]
            lines.append(line)
        parts.append("\n".join(lines))

    # APPOINTMENTS, past + upcoming. Most useful for context like
    # "remember my follow-up next week" or "what did we plan to discuss".
    try:
        appts = list_appointments() or []
    except Exception:
        appts = []
    if appts:
        # Sort by date if present, descending (most recent first).
        try:
            appts_sorted = sorted(appts, key=lambda a: (a.get("date") or ""), reverse=True)
        except Exception:
            appts_sorted = appts
        lines = ["APPOINTMENTS ON FILE:"]
        for a in appts_sorted[:10]:
            head_bits = []
            if a.get("date"):
                head_bits.append(str(a["date"]).strip())
            if a.get("title"):
                head_bits.append(str(a["title"]).strip())
            tail_bits = []
            if a.get("doctor"):
                tail_bits.append("Dr " + str(a["doctor"]).strip())
            if a.get("location"):
                tail_bits.append("at " + str(a["location"]).strip())
            line = "  - " + ", ".join([b for b in head_bits if b])
            if tail_bits:
                line += " (" + ", ".join(tail_bits) + ")"
            notes = (a.get("notes") or "").strip()
            if notes:
                line += ", Note: " + notes[:200]
            lines.append(line)
        parts.append("\n".join(lines))

    # HEALTH RECORDS, uploaded reports/scans. The `summary` field captures
    # extracted text from PDFs and Vision-AI summaries from images, so the
    # assistant CAN actually reason about previously-uploaded content even
    # when those files aren't in the current chat.
    try:
        records = list_health_records() or []
    except Exception:
        records = []
    if records:
        try:
            records_sorted = sorted(records, key=lambda r: (r.get("uploaded_at") or ""), reverse=True)
        except Exception:
            records_sorted = records
        # Prescription records are only safe to use if the name on the
        # script matches the profile owner, otherwise the assistant might
        # discuss someone else's medications as if they were the user's.
        _profile_name = ""
        try:
            _profile_name = (st.session_state.get("patient_name") or "").strip().lower()
        except Exception:
            _profile_name = ""
        def _rx_name_matches(rec):
            rtype = (rec.get("record_type") or "").lower()
            is_rx = (rtype == "prescription") or ((rec.get("name") or "").lower().startswith("prescription"))
            if not is_rx:
                return True  # non-prescription records always included
            rx_name = (rec.get("patient_name") or "").strip().lower()
            if not rx_name:
                return False  # script with no recoverable name → exclude
            if not _profile_name:
                return False
            # Match if profile name appears in rx name or vice-versa
            return (_profile_name in rx_name) or (rx_name in _profile_name)
        records_sorted = [r for r in records_sorted if _rx_name_matches(r)]
        lines = [
            "UPLOADED HEALTH RECORDS (file metadata + AI summary + actual "
            "extracted text, use the 'Key values' field to compare numeric "
            "results across multiple uploads of the same kind):"
        ]
        for r in records_sorted[:8]:
            head = (r.get("name") or "(unnamed)").strip()
            uploaded = (r.get("uploaded_at") or "")[:10]
            ftype = (r.get("file_type") or "").strip()
            line = "  - "
            if uploaded:
                line += uploaded + ": "
            line += head
            if ftype:
                line += " (" + ftype + ")"
            lines.append(line)
            summary = (r.get("summary") or "").strip()
            if summary:
                lines.append("    AI summary: " + summary[:500])
            raw = (r.get("raw_text") or "").strip()
            if raw and raw != summary:
                # Collapse repeated whitespace so it reads cleanly in the prompt.
                raw_clean = re.sub(r"[ \t]+", " ", raw)
                raw_clean = re.sub(r"\n{3,}", "\n\n", raw_clean)
                lines.append("    Key values / extracted text: " + raw_clean[:900])
        parts.append("\n".join(lines))

    # TODAY'S VITALS, heart rate, sleep, steps, water, mood.
    try:
        dm = get_daily_metrics() or {}
    except Exception:
        dm = {}
    vital_lines = []
    if dm.get("heart_rate_resting") is not None:
        vital_lines.append("  - Resting heart rate: " + str(dm["heart_rate_resting"]) + " bpm")
    if dm.get("sleep_hours") is not None:
        vital_lines.append("  - Sleep last night: " + str(dm["sleep_hours"]) + " hours")
    if dm.get("steps") is not None:
        vital_lines.append("  - Steps today: " + str(dm["steps"]))
    wg = dm.get("water_glasses")
    if wg is not None and (isinstance(wg, (int, float)) and wg >= 0):
        vital_lines.append("  - Water intake today: " + str(wg) + "/8 glasses")
    if dm.get("mood"):
        vital_lines.append("  - Mood today: " + str(dm["mood"]))
    if vital_lines:
        parts.append(
            "TODAY'S VITALS (most recent values the patient logged on their "
            "MediChat Health Overview):\n" + "\n".join(vital_lines)
        )

    # ALLERGIES, clinically critical, surface prominently.
    try:
        allergies = list_allergies() or []
    except Exception:
        allergies = []
    if allergies:
        lines = [
            "KNOWN ALLERGIES (clinically critical, ALWAYS check any drug or "
            "treatment suggestion against this list before recommending):"
        ]
        for a in allergies[:25]:
            head = (a.get("name") or "").strip()
            details = []
            sev = (a.get("severity") or "").strip()
            if sev:
                details.append("severity: " + sev)
            rxn = (a.get("reaction") or "").strip()
            if rxn:
                details.append("reaction: " + rxn[:80])
            line = "  - " + head
            if details:
                line += " (" + "; ".join(details) + ")"
            if a.get("notes"):
                line += ", " + a["notes"][:120]
            lines.append(line)
        parts.append("\n".join(lines))

    # FAMILY HISTORY, affects risk modeling for genetic/familial conditions.
    try:
        fh = list_family_history() or []
    except Exception:
        fh = []
    if fh:
        lines = [
            "FAMILY MEDICAL HISTORY (genetic / risk context, use when "
            "assessing the patient's likelihood of related conditions):"
        ]
        for f in fh[:20]:
            cond = (f.get("condition") or "").strip()
            rel = (f.get("relationship") or "").strip()
            line = "  - " + cond
            if rel:
                line += " (" + rel + ")"
            if f.get("age_at_diagnosis"):
                line += ", diagnosed at " + str(f["age_at_diagnosis"])
            if f.get("notes"):
                line += "; " + f["notes"][:120]
            lines.append(line)
        parts.append("\n".join(lines))

    # SURGICAL HISTORY, affects anatomy / drug clearance / future risk.
    try:
        surg = list_surgical_history() or []
    except Exception:
        surg = []
    if surg:
        try:
            surg_sorted = sorted(surg, key=lambda s: (s.get("year") or ""), reverse=True)
        except Exception:
            surg_sorted = surg
        lines = [
            "SURGICAL HISTORY (past procedures, relevant for anatomy, "
            "post-op risks, and drug-clearance assumptions):"
        ]
        for s in surg_sorted[:15]:
            proc = (s.get("procedure") or "").strip()
            year = (s.get("year") or "").strip()
            hosp = (s.get("hospital") or "").strip()
            line = "  - " + proc
            if year:
                line += " (" + year + ")"
            if hosp:
                line += " at " + hosp
            if s.get("notes"):
                line += ", " + s["notes"][:120]
            lines.append(line)
        parts.append("\n".join(lines))

    return "\n\n".join(parts)


# Reasonable symptom keyword set for timeline matching. Kept lowercase for
# substring comparisons. Phrases longer than single words are included for
# specificity (e.g. "chest pain" vs. just "pain").
_SYMPTOM_KEYWORDS = [
    "headache", "migraine", "fever", "cough", "fatigue", "tiredness",
    "shortness of breath", "breathless", "wheezing",
    "chest pain", "chest tight", "palpitations",
    "stomach pain", "abdominal pain", "stomach ache", "bloating",
    "nausea", "vomiting", "diarrhea", "diarrhoea", "constipation",
    "dizziness", "lightheaded", "fainting", "blackout",
    "rash", "itch", "swelling",
    "back pain", "neck pain", "joint pain", "muscle pain",
    "sore throat", "runny nose", "congestion",
    "insomnia", "trouble sleeping", "anxiety", "panic", "depressed",
    "weight loss", "weight gain", "appetite",
    "blurred vision", "vision change", "ringing in ears", "tinnitus",
    "numbness", "tingling", "weakness", "tremor",
    "burning urination", "urinary", "frequent urination",
    "menstrual", "period pain", "cramps",
]


def build_symptom_timeline(current_messages, current_conversation_id=""):
    """Scan past conversations (for authenticated users) plus the current
    chat for symptom mentions, group by symptom, and return a structured
    timeline. Lets the AI surface patterns like "headache reported 4 times
    over the past 3 months" without the patient having to mention them.

    For guests, only the current conversation is scanned (we don't have
    durable storage of past conversations for them).
    """
    occurrences = {}  # symptom → list of "YYYY-MM-DD (snippet)"

    def _scan_text(text, date_str):
        if not text:
            return
        low = text.lower()
        for kw in _SYMPTOM_KEYWORDS:
            if kw in low:
                occurrences.setdefault(kw, []).append(date_str or "unknown date")

    # Current chat, user messages only.
    if current_messages:
        try:
            today = datetime.now().strftime("%Y-%m-%d")
            for m in current_messages:
                if m.get("role") == "user":
                    _scan_text(m.get("content", ""), today)
        except Exception:
            pass

    # Past conversations, authenticated users only.
    if st.session_state.get("is_authenticated") and st.session_state.get("user_email_hash"):
        try:
            convs = list_conversations(st.session_state.user_email_hash, limit=20) or []
        except Exception:
            convs = []
        for c in convs:
            try:
                cid = c.get("id") or ""
                if cid == current_conversation_id:
                    continue  # already scanned via current_messages
                date_str = (c.get("updated_at") or c.get("created_at") or "")[:10] or "earlier chat"
                # Use the cheaper summary fields rather than loading the
                # full conversation, keeps profile-context build fast.
                snippet = " ".join([
                    str(c.get("first_user_msg") or ""),
                    str(c.get("title") or ""),
                    str(c.get("last_assistant_msg") or ""),
                ])
                _scan_text(snippet, date_str)
            except Exception:
                continue

    if not occurrences:
        return ""

    lines = [
        "SYMPTOM TIMELINE (mentions of symptoms across this patient's past "
        "and current chats, useful for spotting recurrence or patterns):"
    ]
    # Sort by frequency descending so the most-reported issues appear first.
    for kw, dates in sorted(occurrences.items(), key=lambda kv: -len(kv[1])):
        unique_dates = sorted(set(dates), reverse=True)
        date_str = ", ".join(unique_dates[:5])
        if len(unique_dates) > 5:
            date_str += ", …"
        lines.append("  - " + kw + ", mentioned " + str(len(dates)) + "× (" + date_str + ")")
    return "\n".join(lines)

