def check_drug_interactions(response_text, memory):
    if not response_text:
        return []
    text_lower = response_text.lower()
    conditions_text = " ".join(memory.get("conditions", [])).lower() + " " + " ".join(memory.get("medications", [])).lower()
    if not conditions_text.strip():
        return []
    alerts = []
    for class_name, info in DRUG_INTERACTIONS.items():
        drug_hit = next((d for d in info["drugs"] if d in text_lower), None)
        if not drug_hit:
            continue
        condition_hits = [c for c in info["conditions"] if c in conditions_text]
        if condition_hits:
            alerts.append({
                "drug": drug_hit.title(),
                "conditions": condition_hits,
                "warning": info["warning"]
            })
    return alerts

def calculate_confidence(distances):
    """Distance→confidence mapping calibrated for this RAG corpus.

    The previous formula (1.8-floor curve) bottomed out at 5% for any normal
    conversational query against a PubMed-style corpus where distances
    typically run 1.4-2.2, making the UI look pessimistic on perfectly
    reasonable questions. This curve is more generous: a typical query
    (avg_dist ~1.5) now lands around 50% rather than 5%.

    Distance reference (smaller = closer match):
      0.4  → 83%   (high)
      0.7  → 74%   (high)
      1.0  → 65%   (medium)
      1.3  → 56%   (medium)
      1.5  → 50%   (medium)
      1.7  → 44%   (low)
      2.0  → 35%   (low)
      2.3  → 26%   (low)
      2.5+ → 20%   (floor)
    """
    if not distances or len(distances) == 0:
        return "low", 20
    avg_dist = sum(distances) / len(distances)
    raw_pct = round(95 - (avg_dist * 30))
    pct = max(20, min(98, raw_pct))
    if avg_dist < 0.9:
        level = "high"
    elif avg_dist < 1.6:
        level = "medium"
    else:
        level = "low"
    return level, pct

def get_sources_used(idxs):
    pubmed_split = max(1, len(documents) // 2)
    pubmed_count = sum(1 for i in idxs if i < pubmed_split)
    dialog_count = sum(1 for i in idxs if i >= pubmed_split)
    sources = []
    if pubmed_count > 0:
        sources.append("PubMed Research (" + str(pubmed_count) + ")")
    if dialog_count > 0:
        sources.append("Doctor-Patient Data (" + str(dialog_count) + ")")
    return sources

def sanitize_rag_context(raw_context):
    if not raw_context:
        return ""
    leaked_meds = [
        "subutex", "neurontin", "gabapentin", "remeron", "mirtazapine",
        "zoloft", "sertraline", "klonopin", "clonazepam", "synthroid",
        "levothyroxine", "xanax", "prozac", "lexapro", "wellbutrin",
        "lisinopril", "metformin", "atorvastatin", "amlodipine",
    ]
    text = raw_context
    patterns_to_strip = [
        r"(?i)i['']?m on [^.]*?\.",
        r"(?i)i take [^.]*?\.",
        r"(?i)i am taking [^.]*?\.",
        r"(?i)i have been on [^.]*?\.",
        r"(?i)i was prescribed [^.]*?\.",
        r"(?i)my medications? (are|include)[^.]*?\.",
        r"(?i)currently on [^.]*?\.",
    ]
    for pat in patterns_to_strip:
        text = re.sub(pat, "", text)
    sentences = re.split(r'(?<=[.!?])\s+', text)
    clean = []
    for s in sentences:
        s_lower = s.lower()
        if any(m in s_lower for m in leaked_meds):
            continue
        clean.append(s)
    result = " ".join(clean).strip()
    return result if len(result) > 100 else raw_context

def markdown_to_html(text):
    if not text:
        return ""

    raw = text
    raw = re.sub(r"^#{1,6}\s+(.+?)$", lambda m: "\n\n**" + m.group(1).strip().rstrip(":") + ":**\n", raw, flags=re.MULTILINE)
    raw = re.sub(r"\s*#{2,6}\s+", " ", raw)
    raw = re.sub(r"(?<=[.!?:\)])\s+\*\s+(?=[A-Z])", "\n- ", raw)
    raw = re.sub(r"\*\*\s*\*\s+(?=[A-Z])", "**\n- ", raw)
    raw = re.sub(r"(?<=[a-zA-Z\.])\s+\*\s+(?=[A-Z])", "\n- ", raw)
    raw = re.sub(r"(?<=[.!?])\s+(\*\*[^\*\n]{2,40}:\*\*)", r"\n\n\1\n\n", raw)
    raw = re.sub(r"(?<=[a-zA-Z\.\)])\s+(?=-\s+[A-Z])", r"\n", raw)
    # ── Inline numbered list normaliser ─────────────────────────────
    # AI models often produce "...common ones: 1. **Tension**: ... 2.
    # **Dehydration**: ... 3. **Migraines**: ..." which Python's
    # markdown parser keeps as ONE paragraph because the items aren't
    # separated by blank lines. Insert a blank line before EVERY
    # number-marker that follows a sentence end so markdown sees a
    # proper ordered list. Single regex done in a loop so we keep
    # promoting numbers until none remain in inline form.
    for _ in range(6):
        new_raw = re.sub(r"([:.!?,])[ \t]+(?=\d{1,2}[\.)][ \t]+\S)", r"\1\n\n", raw)
        if new_raw == raw:
            break
        raw = new_raw
    # Orphaned list numbers: models sometimes emit "1.\n\n**Heading:**"
    # which renders the bare "1." on its own line with the heading below
    # it. Re-join the number with the content that follows it.
    raw = re.sub(r"(^|\n)[ \t]*(\d{1,2})[\.)][ \t]*\n+[ \t]*(?=\*\*|\S)", r"\1\2. ", raw)
    raw = re.sub(r"\n{3,}", "\n\n", raw)

    try:
        import markdown as _md
        html_text = _md.markdown(html.escape(raw, quote=False))
    except ImportError:
        safe = html.escape(raw)
        html_text = "<p>" + safe.replace("\n\n", "</p><p>").replace("\n", "<br>") + "</p>"
        html_text = re.sub(r"\*\*([^\*\n]+)\*\*", r"<strong>\1</strong>", html_text)

    html_text = html_text.replace("<p>", "<p class='md-p'>")
    html_text = html_text.replace("<ul>", "<ul class='md-ul'>")
    html_text = html_text.replace("<ol>", "<ol class='md-ol'>")
    html_text = html_text.replace("<hr>", "<hr class='md-hr'/>")
    html_text = html_text.replace("<hr />", "<hr class='md-hr'/>")
    for level in range(1, 7):
        html_text = re.sub(
            r"<h" + str(level) + r"[^>]*>(.*?)</h" + str(level) + r">",
            r"<p class='md-p'><strong>\1</strong></p>",
            html_text,
            flags=re.DOTALL
        )

    # Dual-model second-opinion marker swap. Markers are inserted in the
    # streaming response (see dispatcher's OpenAI branch). They survive
    # html.escape (brackets are not escaped) and markdown processing (plain
    # text inside <p>), then we swap them here for an explicit styled wrapper
    # that defeats the chat bubble's paragraph-collapsing CSS.
    _verify_open = (
        "<div class='md-verify-block' style='"
        "margin-top:1.4rem;padding-top:1rem;"
        "border-top:1.5px solid #cbd5e1;'>"
        "<div class='md-verify-head' style='display:flex;align-items:flex-start;gap:0.5rem;margin-bottom:0.5rem;'>"
        "<span style='font-size:1.05rem;line-height:1.2;flex-shrink:0;'>🩺</span>"
        "<div style='min-width:0;'>"
        "<div style='font-weight:600;color:#334155;font-size:0.97em;line-height:1.2;letter-spacing:-0.005em;'>MediChat Second Opinion</div>"
        "<div style='font-weight:400;font-style:italic;color:#94a3b8;font-size:0.82em;line-height:1.3;margin-top:0.15rem;'>second medical Ai perspective</div>"
        "</div>"
        "</div>"
        "<div class='md-verify-body' style='"
        "color:#475569;font-style:italic;line-height:1.55;'>"
    )
    _verify_close = "</div></div>"
    html_text = html_text.replace(
        "<p class='md-p'>[[VERIFY_START]]</p>", _verify_open
    )
    html_text = html_text.replace(
        "<p class='md-p'>[[VERIFY_END]]</p>", _verify_close
    )
    # Belt-and-braces: handle the case where markdown left the markers
    # adjacent without paragraph wrapping (rare, but harmless to guard).
    html_text = html_text.replace("[[VERIFY_START]]", _verify_open)
    html_text = html_text.replace("[[VERIFY_END]]", _verify_close)
    return html_text

def strip_excessive_disclaimers(text):
    if not text:
        return text

    # Protect the MediChat Second Opinion block from the whitespace collapse below
    # (the \s{2,} rule was eating the surrounding \n\n separators which
    # broke the marker-swap renderer downstream \u2014 Verify never appeared
    # because its block ended up inline with the primary answer).
    verify_block = ""
    m = re.search(r"\[\[VERIFY_START\]\][\s\S]*?\[\[VERIFY_END\]\]", text)
    if m:
        verify_block = m.group(0)
        text = text[:m.start()] + "@@VERIFY_PLACEHOLDER@@" + text[m.end():]

    patterns = [
        r"\*?\*?Disclaimer:[^\n]*\*?\*?\s*",
        r"\*?\*?Please note:[^\n]*not a doctor[^\n]*\*?\*?\s*",
        r"Please note that I'?m not a doctor[^.]*\.\s*",
        r"I'?m not a doctor[,.]?[^.]*\.\s*",
        r"(I want to|I'd like to) emphasi[sz]e that I'?m not a doctor[^.]*\.\s*",
        r"(My|This) response is not a substitute for professional medical (advice|diagnosis)[^.]*\.\s*",
        r"This (conversation|response) is (not a substitute|for general information)[^.]*\.\s*",
        r"Always consult (with )?a (qualified )?(healthcare|medical) professional[^.]*\.\s*",
        r"Please consult (with )?a (qualified )?(healthcare|medical) professional[^.]*\.\s*",
        r"It'?s (important|essential|crucial) to (consult|speak with) a (doctor|healthcare professional|medical professional)[^.]*\.\s*",
    ]
    cleaned = text
    for pat in patterns:
        cleaned = re.sub(pat, "", cleaned, flags=re.IGNORECASE)

    cleaned = re.sub(r"[ \t]+[\u2014\u2013][ \t]+", ", ", cleaned)
    cleaned = cleaned.replace("\u2014", ", ")
    cleaned = cleaned.replace("\u2013", ", ")
    cleaned = re.sub(r",\s*,", ",", cleaned)
    # CRITICAL: only collapse RUNS OF SPACES/TABS, NEVER newlines.
    # The previous `\s{2,}` was eating the \n\n separators that markdown
    # needs to render numbered / bullet lists as real <ol>/<ul> blocks,
    # so saved messages came back as one long inline paragraph even
    # though streaming looked fine.
    cleaned = re.sub(r"[ \t]{2,}", " ", cleaned)
    cleaned = re.sub(r"\n{3,}", "\n\n", cleaned)
    cleaned = cleaned.strip()

    # Restore the Verify block with double blank lines around it AND
    # between the markers and the body, so markdown produces a
    # standalone <p>[[VERIFY_START]]</p>, then a <p>body</p>, then a
    # <p>[[VERIFY_END]]</p>. The marker-swap in markdown_to_html
    # matches each of those paragraphs and replaces them with the
    # styled block. Single-newline separators left the markers glued
    # to the body, which broke the swap and rendered the block as
    # invisible inline text.
    if verify_block:
        # Normalise internal separators of the recovered block too, # whatever single \n the dispatcher emitted gets bumped to \n\n.
        verify_block = verify_block.replace(
            "[[VERIFY_START]]\n", "[[VERIFY_START]]\n\n"
        ).replace(
            "\n[[VERIFY_END]]", "\n\n[[VERIFY_END]]"
        )
        cleaned = cleaned.replace(
            "@@VERIFY_PLACEHOLDER@@",
            "\n\n" + verify_block + "\n\n"
        )

    return cleaned

def is_casual_message(text):
    if not text:
        return True
    val = text.strip().lower().rstrip("?.! ")
    greetings = {
        "hi", "hello", "hey", "hola", "g'day", "good morning", "good afternoon", "good evening", 
        "howdy", "hi there", "hello there", "yo", "sup", "what's up", "whats up", "what's happening", "whats happening"
    }
    if val in greetings:
        return True
    casual_queries = {
        "how are you", "how are you doing", "how's it going", "hows it going", "what's new", "whats new",
        "who are you", "what is your name", "what are you", "are you there", "tell me a joke", 
        "thanks", "thank you", "ok", "okay"
    }
    if val in casual_queries:
        return True
    return False

def dual_model_review(question, primary_answer, history=None, primary_engine="openai"):
    """Always-visible second opinion from a different model than the
    primary. Returns the reviewer's brief perspective (1-3 sentences) as
    a plain string. Returns empty string only when disabled, no other
    backend is available, primary is empty, or the API call fails, caller appends the result verbatim when truthy.

    Reviewer selection:
      • primary_engine = "openai"  → Claude reviews
      • primary_engine = "claude"  → OpenAI reviews
      • primary_engine = "groq"    → Claude > OpenAI (whichever is up)

    This means MediChat Second Opinion works no matter which backend served the
    primary answer, previously it only fired when OpenAI was primary,
    which left a silent gap whenever OpenAI failed and Claude streamed
    instead.

    history: optional list of prior {role, content} messages so the
    reviewer can correctly handle follow-up questions ("Are you sure?",
    "Why?") that only make sense in context.
    """
    if not ENABLE_DUAL_REVIEW:
        return ""
    if not primary_answer or not primary_answer.strip():
        return ""
    # Decide reviewer = first available backend that isn't the primary.
    # Three-way fallback so Verify works whatever combination of keys is
    # configured on the deployment (Streamlit Cloud often has only 1-2
    # of the three providers set). Order tries the most clinically-tuned
    # reviewer first, then falls back to whatever's available.
    reviewer = ""
    if primary_engine == "openai":
        if CLAUDE_ACTIVE and anthropic_client is not None: reviewer = "claude"
        elif GROQ_ACTIVE and groq_client is not None:      reviewer = "groq"
    elif primary_engine == "claude":
        if OPENAI_ACTIVE and openai_client is not None:    reviewer = "openai"
        elif GROQ_ACTIVE and groq_client is not None:      reviewer = "groq"
    else:  # groq or unknown
        if CLAUDE_ACTIVE and anthropic_client is not None: reviewer = "claude"
        elif OPENAI_ACTIVE and openai_client is not None:  reviewer = "openai"
    if not reviewer:
        # Use logging.warning instead of print(), Streamlit Cloud
        # captures warnings but suppresses stdout. Same goes for all the
        # other diagnostics in this function.
        import logging as _lg
        _lg.warning("[dual_model_review] no reviewer available, primary=" + str(primary_engine) +
                    " claude=" + str(CLAUDE_ACTIVE) + " openai=" + str(OPENAI_ACTIVE) +
                    " groq=" + str(GROQ_ACTIVE))
        st.session_state._verify_debug = "no reviewer available (primary=" + str(primary_engine) + ", claude=" + str(CLAUDE_ACTIVE) + ", openai=" + str(OPENAI_ACTIVE) + ", groq=" + str(GROQ_ACTIVE) + ")"
        return ""
    try:
        # Build a short context block from the last ~3 exchanges so Claude
        # understands follow-up questions. Strip past verify markers so
        # Claude doesn't see its own previous output bleeding into context,
        # and truncate each turn to keep token cost low.
        context_block = ""
        if history:
            recent = [m for m in history if m.get("role") in ("user", "assistant")]
            recent = recent[-6:]
            if recent:
                lines = ["PRIOR CONVERSATION (for context only):"]
                for m in recent:
                    role = m.get("role")
                    content = (m.get("content") or "").strip()
                    # Strip any previous verify block so Claude doesn't see
                    # its own past second-opinions mixed into the transcript.
                    content = re.sub(
                        r"\[\[VERIFY_START\]\].*?\[\[VERIFY_END\]\]",
                        "",
                        content,
                        flags=re.DOTALL,
                    ).strip()
                    if not content:
                        continue
                    if len(content) > 500:
                        content = content[:500].rstrip() + "…"
                    speaker = "Patient" if role == "user" else "Primary AI"
                    lines.append(f"{speaker}: {content}")
                context_block = "\n".join(lines) + "\n\n---\n\n"
        review_prompt = (
            context_block +
            "LATEST EXCHANGE:\n"
            f"Patient: {question}\n\n"
            f"Primary AI answered:\n{primary_answer}\n\n"
            "---\n\n"
            "Your job: write a brief SECOND OPINION (1-3 sentences, max 55 words) "
            "that adds genuine value to the patient. Use the PRIOR CONVERSATION "
            "context to interpret short follow-up questions correctly.\n\n"
            "Choose ONE angle based on what's most useful here:\n"
            "  • Add an important nuance, caveat, or context the primary answer missed.\n"
            "  • Mention a relevant alternative, safer option, or different consideration.\n"
            "  • Flag a safety concern, red-flag symptom, or drug interaction the primary didn't fully address.\n"
            "  • Clarify a common misconception related to the question.\n"
            "  • Confirm the answer and add ONE concise piece of supporting context (only if there's truly nothing else to add).\n\n"
            "Hard rules:\n"
            "- Do NOT rephrase or repeat what the primary answer covered.\n"
            "- Do NOT speculate or invent facts.\n"
            "- Do NOT say things like 'I can't review without knowing the question', use the prior conversation above to understand context.\n"
            "- Do NOT include phrases like 'The primary answer is correct' or 'I agree', go straight to the value.\n"
            "- Write directly to the patient (use 'you' / 'your').\n"
            "- No preamble. Start with the substance.\n\n"
            "Your second-opinion note (1-3 sentences):"
        )
        _sys = ("You are a careful, concise second medical AI giving a brief "
                "value-add second opinion to a patient. Be direct and useful, "
                "not redundant.")
        raw = ""
        if reviewer == "claude":
            resp = anthropic_client.messages.create(
                model=CLAUDE_MODEL,
                max_tokens=220,
                system=_sys,
                messages=[{"role": "user", "content": review_prompt}],
                temperature=0.25,
            )
            if getattr(resp, "content", None):
                for block in resp.content:
                    if hasattr(block, "text"):
                        raw += block.text
        elif reviewer == "openai":
            resp = openai_client.chat.completions.create(
                model=OPENAI_MODEL,
                max_tokens=220,
                temperature=0.25,
                messages=[{"role": "system", "content": _sys},
                          {"role": "user", "content": review_prompt}],
            )
            raw = (resp.choices[0].message.content or "")
        elif reviewer == "groq":
            resp = groq_client.chat.completions.create(
                model="llama-3.3-70b-versatile",
                max_tokens=220,
                temperature=0.25,
                messages=[{"role": "system", "content": _sys},
                          {"role": "user", "content": review_prompt}],
            )
            raw = (resp.choices[0].message.content or "")
        raw = raw.strip()
        # Diagnostic: logged at WARNING level so it appears in Streamlit
        # Cloud's log panel (stdout from print() is silently dropped).
        import logging as _lg
        _lg.warning("[dual_model_review] reviewer=" + reviewer + " raw=" + repr(raw[:200]))
        st.session_state._verify_debug = "reviewer=" + reviewer + ", len=" + str(len(raw)) + " chars"
        if not raw:
            return ""
        # Strip any accidental "Second opinion:" / "Note:" preamble.
        for prefix in ("Second opinion:", "Second Opinion:", "SECOND OPINION:",
                       "Note:", "NOTE:", "Important:", "IMPORTANT:"):
            if raw.startswith(prefix):
                raw = raw[len(prefix):].strip()
                break
        # Defensive length cap.
        if len(raw) > 600:
            raw = raw[:600].rstrip() + "…"
        return raw
    except Exception as e:
        import logging as _lg
        _lg.warning("[dual_model_review] reviewer=" + reviewer + " call FAILED: " + str(e)[:300])
        st.session_state._verify_debug = "reviewer=" + reviewer + " call failed: " + str(e)[:120]
        return ""


# ════════════════════════════════════════════════════════════════════
# Adaptive Memory Layer, MediChat's "self-learning" per-user system.
#
# This is an HONEST self-learning implementation: we never re-train the
# underlying LLMs (Claude/OpenAI/Groq), those weights are frozen and
# fine-tuning them on raw medical conversations would be unsafe + breach
# patient privacy across users. What we DO is build a private,
# per-patient adaptive layer that:
#
#   1. Auto-extracts structured facts from each chat message (allergies,
#      medications, conditions, symptoms, appointments) using a small
#      Claude/OpenAI call and silently grows the user's profile.
#   2. Embeds past chats and retrieves the most relevant prior exchanges
#      when a new question is asked, so MediChat remembers "you asked
#      about this last month".
#   3. Learns the user's preferred answer style from thumbs-up/down
#      feedback and message-length patterns.
#   4. Surfaces cross-time correlations between metrics (sleep, HR,
#      steps) and symptom mentions, patterns the user might miss.
#
# All four layers feed back into the system prompt of the next chat
# turn, so MediChat genuinely *adapts* over time without ever touching
# the foundation models.
# ════════════════════════════════════════════════════════════════════

_DEFAULT_STYLE_PREFS = {
    "depth": "balanced",         # concise | balanced | detailed
    "tone": "warm",              # warm | clinical | direct
    "technical_level": "plain",  # plain | mixed | technical
    "thumbs_up": 0,
    "thumbs_down": 0,
    "avg_user_msg_len": 0.0,
    "msg_count_sampled": 0,
    "last_updated": "",
}

def get_style_preferences():
    if st.session_state.get("is_authenticated"):
        prefs = (get_user_doc() or {}).get("style_preferences", {}) or {}
    else:
        prefs = _ensure_guest_store().setdefault("style_preferences", {}) or {}
    out = dict(_DEFAULT_STYLE_PREFS)
    out.update(prefs)
    return out

def update_style_preferences(patch):
    cur = get_style_preferences()
    cur.update(patch or {})
    cur["last_updated"] = datetime.now().isoformat(timespec="seconds")
    if st.session_state.get("is_authenticated"):
        update_user_doc({"style_preferences": cur})
    else:
        _ensure_guest_store()["style_preferences"] = cur
    return cur

def adapt_style_from_message(user_msg, feedback=None):
    """Incremental style learning. Called after every user message.

    Heuristics (cheap, deterministic, no LLM call needed):
      • Short user messages (< 12 words) → user prefers concise answers.
      • Long detailed user messages → user wants depth, mirror their level.
      • Frequent thumbs-up on long answers → prefers detailed.
      • Frequent thumbs-down on long answers → prefers concise.
      • Use of medical jargon (e.g. "HbA1c", "BP", "GFR") → technical level.
    """
    if not user_msg:
        return
    prefs = get_style_preferences()
    words = (user_msg or "").split()
    wlen = len(words)
    # Rolling average of user message length (last ~20 samples).
    n = max(1, int(prefs.get("msg_count_sampled", 0)))
    new_avg = (prefs.get("avg_user_msg_len", 0.0) * min(n, 20) + wlen) / (min(n, 20) + 1)
    prefs["avg_user_msg_len"] = round(new_avg, 1)
    prefs["msg_count_sampled"] = min(n + 1, 100)
    # Depth, based on rolling average length.
    if prefs["avg_user_msg_len"] < 8:
        prefs["depth"] = "concise"
    elif prefs["avg_user_msg_len"] > 35:
        prefs["depth"] = "detailed"
    else:
        prefs["depth"] = "balanced"
    # Technical level, jargon detector.
    jargon = ["hba1c", "bp", "gfr", "ldl", "hdl", "tsh", "egfr", "wbc", "rbc", "mri", "ct scan",
              "ecg", "ekg", "echo", "ssri", "snri", "beta blocker", "ace inhibitor", "statin",
              "metformin", "warfarin", "anticoagulant", "thyroid"]
    lo = (user_msg or "").lower()
    if any(j in lo for j in jargon):
        prefs["technical_level"] = "technical" if prefs.get("technical_level") in ("technical", "mixed") else "mixed"
    # Persist.
    update_style_preferences(prefs)

def record_message_feedback(thumbs):
    """Called from the 👍 / 👎 UI buttons. `thumbs` is +1 or -1."""
    prefs = get_style_preferences()
    if thumbs > 0:
        prefs["thumbs_up"] = int(prefs.get("thumbs_up", 0)) + 1
    elif thumbs < 0:
        prefs["thumbs_down"] = int(prefs.get("thumbs_down", 0)) + 1
        # On negative feedback, gently nudge toward concise + warmer.
        if prefs.get("depth") == "detailed":
            prefs["depth"] = "balanced"
        elif prefs.get("depth") == "balanced":
            prefs["depth"] = "concise"
    update_style_preferences(prefs)

def build_style_directive():
    """Render style preferences as a one-line directive for the system prompt."""
    prefs = get_style_preferences()
    d = prefs.get("depth", "balanced")
    t = prefs.get("technical_level", "plain")
    tone = prefs.get("tone", "warm")
    depth_phrase = {
        "concise":   "Keep answers tight, 3,5 sentences max unless the user asks for detail.",
        "balanced":  "Match the user's typical message length; explain key things but don't pad.",
        "detailed":  "The user welcomes depth, feel free to go into mechanism + practical detail.",
    }.get(d, "Match the user's typical message length.")
    tech_phrase = {
        "plain":     "Use plain English, define any clinical term you introduce.",
        "mixed":     "Use clinical terms where useful but always with a short plain-English gloss.",
        "technical": "The user is comfortable with clinical terminology, you can use it freely.",
    }.get(t, "Use plain English.")
    return "Adaptive style, Depth: " + d + "; Tone: " + tone + "; Technical: " + t + ". " + depth_phrase + " " + tech_phrase

# ── 1. Auto-extract facts from chat ─────────────────────────────────
_FACT_EXTRACT_SYSTEM = (
    "You are a careful clinical NLP extractor. Read the user's chat message and return ONLY a strict JSON "
    "object with these keys (each is a list of short strings; empty list if none): "
    "allergies, medications, conditions, symptoms. Plus appointment (object with title, date_iso, doctor, "
    "location, or null). Plus confidence (high|medium|low). Rules:\n"
    "- Only extract facts the USER says about THEMSELVES (first person).\n"
    "- Skip negations (e.g. 'I'm NOT allergic to peanuts' → don't extract).\n"
    "- Skip past-only mentions ('I used to take X' → skip).\n"
    "- Allergies: just the substance + (severity if stated).\n"
    "- Medications: just 'name dose freq' if stated.\n"
    "- Conditions: chronic diagnoses (diabetes, asthma, hypertension), NOT today's symptoms.\n"
    "- Symptoms: short noun phrase (e.g. 'headache 3 days', 'sharp chest pain').\n"
    "- Appointment: only if user says they HAVE BOOKED one (not 'I should book').\n"
    "- Date format: YYYY-MM-DDTHH:MM if specified, else null.\n"
    "Return only JSON, no markdown fences."
)

def adaptive_extract_facts(user_msg, recent_assistant_msg=""):
    """Run a lightweight LLM extraction over the user's latest message.

    Returns a dict with keys allergies/medications/conditions/symptoms/
    appointment/confidence, or None if extraction failed or the message
    is clearly chit-chat.
    """
    if not user_msg or len(user_msg.strip()) < 8:
        return None
    txt_lo = user_msg.lower()
    # Skip obvious non-medical messages to save tokens.
    triggers = ["i have", "i'm", "im ", "i am", "i feel", "i was", "i take", "i'm on", "im on",
                "allerg", "allerg", "diagnos", "prescrib", "mg", "appoint", "booked", "scheduled",
                "dr ", "dr.", "clinic", "hospital", "next week", "tomorrow", "tuesday", "monday",
                "wednesday", "thursday", "friday", "saturday", "sunday"]
    if not any(t in txt_lo for t in triggers):
        return None

    prompt = "User just said:\n" + user_msg.strip()[:1200]
    if recent_assistant_msg:
        prompt += "\n\nPrior assistant turn (context only):\n" + recent_assistant_msg.strip()[:400]

    raw = ""
    try:
        if OPENAI_ACTIVE:
            r = openai_client.chat.completions.create(
                model=OPENAI_MODEL, temperature=0.0, max_tokens=380,
                response_format={"type": "json_object"},
                messages=[{"role": "system", "content": _FACT_EXTRACT_SYSTEM}, {"role": "user", "content": prompt}],
            )
            raw = (r.choices[0].message.content or "").strip()
        elif CLAUDE_ACTIVE:
            resp = anthropic_client.messages.create(
                model=CLAUDE_MODEL, max_tokens=380, temperature=0.0,
                system=_FACT_EXTRACT_SYSTEM,
                messages=[{"role": "user", "content": prompt}],
            )
            raw = (resp.content[0].text or "").strip()
    except Exception as e:
        print("Adaptive fact extraction failed:", e)
        return None

    if not raw:
        return None
    # Strip markdown fences if any
    raw = re.sub(r"^```(?:json)?\s*|\s*```$", "", raw.strip(), flags=re.IGNORECASE)
    try:
        import json as _j
        data = _j.loads(raw)
        if not isinstance(data, dict):
            return None
        data.setdefault("allergies", [])
        data.setdefault("medications", [])
        data.setdefault("conditions", [])
        data.setdefault("symptoms", [])
        data.setdefault("appointment", None)
        data.setdefault("confidence", "medium")
        return data
    except Exception as e:
        print("Adaptive fact extraction JSON parse failed:", e, raw[:200])
        return None

def apply_extracted_facts(facts):
    """Silently merge extracted facts into the patient profile.

    Returns a list of human-readable strings describing what was added,
    so the UI can show a tiny "MediChat noticed and saved: …" chip
    under the next assistant reply.
    """
    if not facts:
        return []
    noticed = []
    try:
        existing_allergies = {(a.get("name") or "").strip().lower() for a in (list_allergies() or [])}
        for item in (facts.get("allergies") or [])[:5]:
            name = (item or "").strip()
            if not name or name.lower() in existing_allergies:
                continue
            if add_allergy(name):
                noticed.append("allergy: " + name[:50])
                existing_allergies.add(name.lower())
    except Exception as e:
        print("apply_extracted_facts allergies failed:", e)
    try:
        existing_meds = {(m.get("name") or "").strip().lower() for m in (list_medications() or [])}
        for item in (facts.get("medications") or [])[:5]:
            s = (item or "").strip()
            if not s:
                continue
            # Parse "name dose freq" loosely
            parts = s.split()
            name = parts[0]
            dose = ""
            freq = ""
            for p in parts[1:]:
                pl = p.lower()
                if re.search(r"\d", p) and ("mg" in pl or "mcg" in pl or "ml" in pl or "g" == pl[-1:]):
                    dose = (dose + " " + p).strip()
                elif pl in ("daily", "twice", "tid", "bid", "qid", "morning", "night", "evening"):
                    freq = (freq + " " + p).strip()
            if name.lower() in existing_meds:
                continue
            if add_medication(name, dose, freq or "Once daily", ""):
                noticed.append("medication: " + s[:50])
                existing_meds.add(name.lower())
    except Exception as e:
        print("apply_extracted_facts meds failed:", e)
    try:
        mem = st.session_state.patient_memory or {"symptoms": [], "conditions": [], "medications": []}
        existing_cond = {c.lower() for c in (mem.get("conditions") or [])}
        for item in (facts.get("conditions") or [])[:5]:
            c = (item or "").strip()
            if not c or c.lower() in existing_cond:
                continue
            mem.setdefault("conditions", []).append(c)
            existing_cond.add(c.lower())
            noticed.append("condition: " + c[:50])
        existing_sym = {s.lower() for s in (mem.get("symptoms") or [])}
        for item in (facts.get("symptoms") or [])[:5]:
            s = (item or "").strip()
            if not s or s.lower() in existing_sym:
                continue
            mem.setdefault("symptoms", []).append(s)
            existing_sym.add(s.lower())
            noticed.append("symptom: " + s[:50])
        st.session_state.patient_memory = mem
    except Exception as e:
        print("apply_extracted_facts memory failed:", e)
    try:
        appt = facts.get("appointment")
        if isinstance(appt, dict) and appt.get("title") and appt.get("date_iso"):
            ok = add_appointment(
                appt.get("title", ""),
                appt.get("date_iso", ""),
                appt.get("doctor", ""),
                appt.get("location", ""),
                "",
                source="chat",
            )
            if ok:
                noticed.append("appointment: " + appt.get("title", "")[:50])
    except Exception as e:
        print("apply_extracted_facts appointment failed:", e)
    return noticed

# ── 2. Embed + retrieve past chats ──────────────────────────────────
def _retrieval_corpus_key():
    if st.session_state.get("is_authenticated"):
        return "u:" + (st.session_state.get("user_email_hash") or "anon")
    return "guest"

def build_past_chat_corpus():
    """Assemble (text, meta) pairs from saved conversations for retrieval."""
    pairs = []
    try:
        if st.session_state.is_authenticated and st.session_state.user_email_hash:
            convs = list_conversations(st.session_state.user_email_hash, limit=30) or []
        else:
            convs = []
        for c in convs:
            msgs = c.get("messages") or []
            # Build user→assistant pairs
            prev_user = None
            for m in msgs:
                role = m.get("role")
                text = (m.get("content") or "").strip()
                if not text:
                    continue
                if role == "user":
                    prev_user = text
                elif role == "assistant" and prev_user:
                    blob = "Q: " + prev_user[:400] + "\nA: " + text[:600]
                    pairs.append((blob, {
                        "conv_id": c.get("id"),
                        "title": (c.get("title") or "")[:100],
                        "ts": c.get("updated_at") or c.get("created_at") or "",
                    }))
                    prev_user = None
                if len(pairs) > 200:
                    break
        # Also append current in-session messages
        cur = st.session_state.get("messages") or []
        prev_user = None
        for m in cur:
            role = m.get("role")
            text = (m.get("content") or "").strip()
            if not text:
                continue
            if role == "user":
                prev_user = text
            elif role == "assistant" and prev_user:
                blob = "Q: " + prev_user[:400] + "\nA: " + text[:600]
                pairs.append((blob, {"conv_id": "current", "title": "Current session", "ts": ""}))
                prev_user = None
    except Exception as e:
        print("build_past_chat_corpus failed:", e)
    return pairs

def retrieve_relevant_past_chats(query, k=3):
    """Semantic retrieval over the user's own past chat Q&A pairs.
    Cached per (corpus_key, version) so we don't re-embed every turn."""
    if not query or len(query.strip()) < 6:
        return []
    key = _retrieval_corpus_key()
    cache = st.session_state.setdefault("_past_chat_index", {})
    pairs = build_past_chat_corpus()
    sig = len(pairs)  # cheap freshness sig
    if cache.get("key") != key or cache.get("sig") != sig or "embeddings" not in cache:
        if not pairs:
            cache.update({"key": key, "sig": sig, "embeddings": None, "pairs": []})
            return []
        try:
            texts = [p[0] for p in pairs]
            emb = embedder.encode(texts, show_progress_bar=False).astype("float32")
            cache.update({"key": key, "sig": sig, "embeddings": emb, "pairs": pairs})
        except Exception as e:
            print("past-chat embedding failed:", e)
            return []
    emb = cache.get("embeddings")
    pairs = cache.get("pairs") or []
    if emb is None or not len(pairs):
        return []
    try:
        q_emb = embedder.encode([query], show_progress_bar=False).astype("float32")
        # Cosine similarity via dot product on L2-normed vectors.
        import numpy as _np
        a = q_emb / (_np.linalg.norm(q_emb, axis=1, keepdims=True) + 1e-9)
        b = emb / (_np.linalg.norm(emb, axis=1, keepdims=True) + 1e-9)
        scores = (a @ b.T)[0]
        top_idx = scores.argsort()[::-1][:max(1, int(k))]
        out = []
        for i in top_idx:
            if scores[i] < 0.35:  # too dissimilar, skip
                continue
            out.append({"text": pairs[i][0], "meta": pairs[i][1], "score": float(scores[i])})
        return out
    except Exception as e:
        print("past-chat retrieval failed:", e)
        return []

def build_past_chat_retrieval_context(query, k=3):
    """Render top-k retrieval results as a system-prompt block."""
    hits = retrieve_relevant_past_chats(query, k=k)
    if not hits:
        return ""
    lines = ["RELEVANT PRIOR CONVERSATIONS (this patient's own past Q&A, use only if directly relevant):"]
    for h in hits:
        ts = (h.get("meta", {}).get("ts") or "")[:10]
        title = h.get("meta", {}).get("title") or ""
        prefix = "  - "
        if ts:
            prefix += "[" + ts + "] "
        if title and title != "Current session":
            prefix += "(" + title[:40] + ") "
        lines.append(prefix + h["text"][:700])
    return "\n".join(lines)

# ── 4. Personal pattern / correlation detection ─────────────────────
def detect_personal_patterns():
    """Cross-correlate the last 7-day metrics with current symptoms +
    chat-extracted symptom timeline. Returns a list of short observations,
    each grounded in the actual numeric pattern (not LLM-generated)."""
    out = []
    try:
        hist = get_metrics_history(7) or []
    except Exception:
        return out
    if len(hist) < 4:
        return out
    sleeps = [(d, m.get("sleep_hours")) for d, m in hist if isinstance(m.get("sleep_hours"), (int, float))]
    hrs = [(d, m.get("heart_rate_resting")) for d, m in hist if isinstance(m.get("heart_rate_resting"), (int, float)) and m.get("heart_rate_resting") > 0]
    steps = [(d, m.get("steps")) for d, m in hist if isinstance(m.get("steps"), (int, float)) and m.get("steps") > 0]
    moods = [(d, m.get("mood")) for d, m in hist if m.get("mood")]
    # Pattern A: low sleep → next-day high HR
    if len(sleeps) >= 4 and len(hrs) >= 4:
        sleep_map = dict(sleeps)
        hr_map = dict(hrs)
        coupled = 0
        total = 0
        for d, s in sleeps:
            try:
                next_day = (datetime.strptime(d, "%Y-%m-%d") + timedelta(days=1)).strftime("%Y-%m-%d")
            except Exception:
                continue
            if next_day in hr_map and s is not None:
                total += 1
                if s < 6 and hr_map[next_day] > (sum(h for _, h in hrs) / len(hrs)) + 4:
                    coupled += 1
        if total >= 3 and coupled >= 2:
            out.append("On days after sleeping <6 h, your resting HR tends to rise 4+ bpm above your weekly average.")
    # Pattern B: low steps day → low mood next day
    if len(steps) >= 4 and len(moods) >= 3:
        step_map = dict(steps)
        low_mood = {d for d, m in moods if str(m).lower() in {"sad", "low", "down", "anxious", "stressed", "😟", "😞", "😢"}}
        if low_mood:
            triggers = 0
            for d in low_mood:
                try:
                    prev = (datetime.strptime(d, "%Y-%m-%d") - timedelta(days=1)).strftime("%Y-%m-%d")
                except Exception:
                    continue
                if prev in step_map and step_map[prev] < 3500:
                    triggers += 1
            if triggers >= 2:
                out.append("Low-mood days often follow days under 3,500 steps, light movement looks protective for you.")
    # Pattern C: hydration consistency
    waters = [int(m.get("water_glasses") or 0) for _, m in hist]
    if waters and (sum(1 for w in waters if w < 3) >= 4):
        out.append("Hydration has been under 3 glasses on 4+ of the last 7 days, this often shows up later as headaches or fatigue.")
    return out

def medichat_rag_stream(question, all_messages, lang_instruction="", patient_name="", pdf_context="", image_context="", past_chats_summary=""):
    if is_casual_message(question):
        clean_context = ""
        sources = []
        confidence_level = None
        confidence_pct = 0
    else:
        emb = embedder.encode([question]).astype("float32")
        distances, idxs = index.search(emb, k=6)
        raw_context = "\n\n---\n\n".join([documents[i] for i in idxs[0]])
        clean_context = sanitize_rag_context(raw_context)
        sources = get_sources_used(idxs[0])
        confidence_level, confidence_pct = calculate_confidence(distances[0].tolist())
        
    memory = extract_patient_memory(all_messages)
    memory_context = build_memory_context(memory)

    history = []
    for m in all_messages[-12:]:
        if m.get("type") == "text":
            history.append({"role": m["role"], "content": m["content"]})

    last_user_message = question.lower() if question else ""
    dissatisfaction_signals = [
        "not helping", "isn't helping", "not useful", "doesn't help",
        "you are not helping", "keep repeating", "already said", "same thing",
        "useless", "unhelpful", "rude", "cold",
    ]
    escalation_needed = any(sig in last_user_message for sig in dissatisfaction_signals)
    tone_complaint = any(w in last_user_message for w in ["rude", "cold", "robotic", "unfriendly"])

    system = (
        "You are MediChat, a warm, thoughtful AI health companion. "
        "You care about the person in front of you. You speak like a caring GP who happens to also be a good friend: "
        "kind, genuinely interested, never robotic, never preachy.\n\n"

        "HARD RULES (NEVER BREAK THESE)\n\n"

        "RULE 1, YOU ARE THIS PATIENT'S PERSONAL VIRTUAL GP:\n"
        "You have READ-ACCESS to their MediChat chart. Three blocks below describe THIS "
        "specific patient and are AUTHORITATIVE:\n"
        "  • <patient_profile>, data the patient explicitly SAVED to their MediChat profile "
        "(medications, appointments, uploaded health records with extracted summaries, today's "
        "vitals). These records ARE PRE-LOADED into your context every turn, you do not need "
        "to ask the patient to re-share them. Reference specific entries by name when relevant. "
        "If asked 'what meds do I take' you MUST list the medications from <patient_profile> "
        "rather than asking them. If asked 'have you looked at my blood report' and a relevant "
        "record summary is in <patient_profile>, you MUST refer to it directly (e.g. 'Yes, "
        "looking at your blood report from 2026-05-15, your HbA1c was…').\n"
        "  • <patient_history>, symptoms / conditions / medications extracted from this and "
        "previous conversations with you.\n"
        "  • The conversation turns themselves.\n"
        "The <reference_knowledge> block is generic medical information and does NOT describe "
        "this patient.\n\n"
        "FORBIDDEN PHRASES, never use these when <patient_profile> contains the answer:\n"
        "  • 'I don't have access to your records'\n"
        "  • 'I can't check your records in real time'\n"
        "  • 'I won't be able to analyze them directly'\n"
        "  • 'You can share relevant details from those reports'\n"
        "  • 'If you save your reports I can reference them' (you ALREADY can, they're above)\n"
        "These phrases break trust. If the profile is empty for a topic, just say what you "
        "see ('your profile doesn't have any blood reports saved yet') and offer to look "
        "when they upload one.\n\n"
        "CONVERSELY, you must NEVER fabricate. Do not say 'you mentioned', 'you said', "
        "'you told me', or 'you're taking' unless the thing referenced appears LITERALLY in "
        "<patient_profile>, <patient_history>, or in the conversation turns.\n\n"

        "COMPARE RECORDS OVER TIME:\n"
        "The UPLOADED HEALTH RECORDS section in <patient_profile> lists records "
        "newest-first. When the patient asks about progress, change, or trends "
        "('am I better?', 'how do my numbers look this time?', 'what changed since "
        "last time?', 'is my X improving?'), or when you notice multiple records of "
        "the same kind (two blood tests, three scans, repeat lipid panels, etc.), "
        "you MUST compare them directly and cite both dates. Pull specific numbers "
        "from the 'Key values' field on each record. Example: 'Comparing your blood "
        "report from 2026-02-15 to today's, your HbA1c dropped from 6.4% to 5.9%, "
        "that is a meaningful improvement consistent with the Metformin you started "
        "in March.' Be honest when a value got worse too, patients deserve the truth.\n"
        "This applies to ANY medical record: blood reports, urine tests, "
        "X-rays, MRIs, CTs, ultrasounds, ECGs, skin photos, allergy results, "
        "spirometry, vaccination records, discharge summaries, doctor letters. "
        "Identify pairs / series of the same type and walk the patient through "
        "what changed.\n\n"

        "RULE 2, RED FLAG SCREENING FIRST:\n"
        "For these presentations, screen for danger signs BEFORE general advice:\n"
        "Sudden/severe headache, chest pain, sudden SOB, severe abdominal pain, neuro symptoms.\n"
        "If red flags present: advise emergency care clearly and without hedging.\n\n"

        "RULE 3, NO REPETITION:\n"
        "Look at your own previous messages in this conversation. Never repeat the same advice twice. "
        "Each response must add something new.\n\n"

        "RULE 4, ONE DISCLAIMER MAX:\n"
        "The app already shows a disclaimer. Only add 'consult a doctor' phrasing when it's genuinely the most important thing to say. "
        "Do NOT end every response with a disclaimer.\n\n"

        "RULE 5, NO EM-DASHES OR EN-DASHES:\n"
        "Never use em-dashes (\u2014) or en-dashes (\u2013) in your responses. Use commas, semicolons, colons, periods.\n\n"

        "RULE 6, NO MARKDOWN HEADINGS:\n"
        "Never use # ## ### markdown headings. If you need a section label, write it as a short bold line: **Section label:** then continue on a new line.\n\n"

        "RULE 7, FORMAT LISTS PROPERLY:\n"
        "When you list multiple items (causes, symptoms, steps, etc.), put EACH item on its OWN line:\n"
        "  - For bullet lists, start each line with '- ' (dash space).\n"
        "  - For numbered lists, start each line with '1. ', '2. ', '3. ' etc.\n"
        "  - Add a blank line BEFORE the first list item so it renders as a real list, not inline text.\n"
        "  - NEVER cram numbered items onto one line ('1. X 2. Y 3. Z'). Always break them across lines.\n"
        "  - Keep each item to ONE sentence when possible. If you need more detail, the detail goes on the same line, not a new bullet.\n\n"

        "RULE 7, NO REPEATED GREETINGS OR RESTATEMENTS:\n"
        "ONLY greet the patient in your VERY FIRST message. On every subsequent turn, jump straight into your answer.\n"
        "NEVER start with 'Hi there', 'Hi [name]', 'Hello', or any greeting after the first turn.\n"
        "NEVER start responses with 'I can see you've uploaded...', 'Looking at your blood work...', 'Based on your report...', 'Thanks for sharing...'\n\n"

        "RULE 8, MATCH RESPONSE LENGTH TO QUESTION:\n"
        "Short casual questions get short conversational answers (1-3 sentences). "
        "Long detailed questions get structured answers with bold labels.\n\n"

        "RULE 9, REMEMBER THE CONVERSATION:\n"
        "If the patient already shared something, DO NOT ask them to repeat it.\n\n"

        "RULE 10, CLINICAL GUARDRAILS:\n"
        "Do not give a final diagnosis. Do not prescribe medicine. Do not provide exact dosage calculations or dose changes. "
        "Use risk-aware language, safety-net advice, and escalation triggers.\n\n"
    )

    if tone_complaint:
        system += (
            "TONE FEEDBACK DETECTED:\n"
            "The patient has told you your tone felt off. "
            "Apologize briefly and genuinely in ONE short sentence, then show warmth.\n\n"
        )

    if escalation_needed:
        system += (
            "ESCALATION TRIGGER:\n"
            "The patient said your previous responses weren't helpful. This response must be noticeably different: "
            "more specific, more committed, with a concrete intervention.\n\n"
        )

    if patient_name:
        system += "Patient's first name: " + patient_name + ". Use naturally and sparingly (max once per response).\n\n"
    if lang_instruction:
        system += lang_instruction + "\n\n"

    # Pull all explicitly-saved profile data (meds, appointments, records,
    # vitals, allergies, family hx, surgical hx) plus a symptom timeline
    # scanned across past conversations.
    profile_context = build_user_profile_context()
    try:
        timeline_context = build_symptom_timeline(
            all_messages,
            st.session_state.get("current_conversation_id", ""),
        )
    except Exception:
        timeline_context = ""
    if timeline_context:
        profile_context = (
            (profile_context + "\n\n") if profile_context else ""
        ) + timeline_context
    if profile_context:
        system += (
            "<patient_profile>\n"
            "This is the patient's saved MediChat profile. Treat this as authoritative "
            "ground truth about who they are and what they're on. Reference specific "
            "entries by name when relevant to their question.\n\n"
            + profile_context + "\n"
            "</patient_profile>\n\n"
        )

    system += "<patient_history>\n"
    if memory_context:
        system += "What this patient has told you across all your conversations with them:\n" + memory_context + "\n"
    else:
        system += "This patient has NOT stated any conditions, medications, or chronic illnesses yet. Do not assume any exist.\n"
    system += "</patient_history>\n\n"

    if past_chats_summary:
        system += (
            "<past_conversations>\n"
            "This patient has had earlier separate conversations with you. Use these to recognise references "
            "to 'last time' or 'remember when'. Each entry shows when the chat happened, its main topic, and a short summary.\n"
            + past_chats_summary +
            "\n</past_conversations>\n\n"
            "When the patient asks if you remember a past chat, refer to <past_conversations> by topic naturally. "
            "Do not say 'I have no memory'. You DO have access to the topics and summaries listed above.\n\n"
        )

    if pdf_context:
        system += (
            "<recent_uploaded_report>\n"
            "IMPORTANT: The patient JUST uploaded this medical report and you already analyzed it. "
            "ANY question they ask now is likely a follow-up to this report. "
            "REPORT CONTENT:\n"
            + pdf_context[:6000]
            + "\n</recent_uploaded_report>\n\n"
        )

    if image_context:
        system += (
            "<recent_uploaded_image>\n"
            "IMPORTANT: The patient JUST uploaded a medical image and you already analyzed it visually. "
            "ANY question they ask now is likely a follow-up about that image. "
            "YOUR EARLIER VISUAL ANALYSIS:\n"
            + image_context[:3000]
            + "\n</recent_uploaded_image>\n\n"
        )

    system += (
        "<reference_knowledge>\n"
        "The following is generic medical information retrieved to help you reason about this query. "
        "It is NOT about the current patient.\n\n"
        + clean_context + "\n"
        "</reference_knowledge>\n"
    )

    full_response = ""

    # Backend order: OpenAI (primary) → Claude Haiku (backup) → Groq (last resort).
    if OPENAI_ACTIVE:
        try:
            openai_msgs = [{"role": "system", "content": system}] + history + [{"role": "user", "content": question}]
            stream = openai_client.chat.completions.create(
                model=OPENAI_MODEL,
                messages=openai_msgs,
                temperature=0.55,
                max_tokens=1024,
                stream=True,
            )
            for chunk in stream:
                delta = ""
                try:
                    delta = chunk.choices[0].delta.content or ""
                except Exception:
                    delta = ""
                if delta:
                    full_response += delta
                    yield ("chunk", delta, full_response)

            # Dual-model second opinion (always visible when Claude is configured).
            # The primary answer has already finished streaming to the patient;
            # this appends a brief value-add perspective from MediChat Second Opinion
            # below, clearly separated as its own paragraph block. Silent only
            # if Claude is disabled, not configured, or the call fails.
            review_text = dual_model_review(question, full_response, history=history, primary_engine="openai")
            if review_text:
                # Use marker-pattern that survives markdown's smart-typography
                # and the chat bubble's CSS paragraph collapsing. Markers are
                # plain ASCII strings that markdown leaves untouched, then
                # markdown_to_html() swaps them for explicit styled <div>s
                # AFTER the markdown pass, guaranteeing a visible separator,
                # bold heading on its own line, and an italic body block
                # that's clearly distinct from the primary answer above.
                # Double blank lines on every side so markdown wraps each
                # marker in its OWN <p>, which the swap then turns into
                # the styled block. Single \n separators (the original)
                # left markers glued to the verify body, breaking the
                # swap and rendering the block as invisible inline text.
                appended = (
                    "\n\n[[VERIFY_START]]\n\n"
                    f"{review_text}\n\n"
                    "[[VERIFY_END]]\n\n"
                )
                full_response += appended
                yield ("chunk", appended, full_response)

            engine_label = "openai+claude_review" if review_text else "openai"
            yield ("done", full_response, {"memory": memory, "sources": sources, "confidence": confidence_level, "confidence_pct": confidence_pct, "engine": engine_label, "verify_text": review_text})
            return
        except Exception as e:
            print("OpenAI stream failed, falling back to Claude/Groq:", e)
            full_response = ""

    if CLAUDE_ACTIVE:
        try:
            anthropic_messages = history + [{"role": "user", "content": question}]
            normalized = []
            for m in anthropic_messages:
                role = m["role"]
                if role not in ("user", "assistant"):
                    continue
                content = m.get("content", "")
                if normalized and normalized[-1]["role"] == role:
                    normalized[-1]["content"] += "\n\n" + content
                else:
                    normalized.append({"role": role, "content": content})
            if not normalized or normalized[0]["role"] != "user":
                normalized = [{"role": "user", "content": question}]

            with anthropic_client.messages.stream(
                model=CLAUDE_MODEL,
                max_tokens=1024,
                system=system,
                messages=normalized,
                temperature=0.55,
            ) as claude_stream:
                for text in claude_stream.text_stream:
                    if text:
                        full_response += text
                        yield ("chunk", text, full_response)
            # Verify also fires when Claude is the primary, reviewer
            # switches to OpenAI so it's still a different model giving
            # the second opinion.
            review_text = dual_model_review(question, full_response, history=history, primary_engine="claude")
            if review_text:
                # Double blank lines on every side so markdown wraps each
                # marker in its OWN <p>, which the swap then turns into
                # the styled block. Single \n separators (the original)
                # left markers glued to the verify body, breaking the
                # swap and rendering the block as invisible inline text.
                appended = (
                    "\n\n[[VERIFY_START]]\n\n"
                    f"{review_text}\n\n"
                    "[[VERIFY_END]]\n\n"
                )
                full_response += appended
                yield ("chunk", appended, full_response)
            engine_label = "claude+openai_review" if review_text else "claude"
            yield ("done", full_response, {"memory": memory, "sources": sources, "confidence": confidence_level, "confidence_pct": confidence_pct, "engine": engine_label, "verify_text": review_text})
            return
        except Exception as e:
            print("Claude stream failed, falling back to Groq:", e)
            full_response = ""

    if groq_client is None:
        raise RuntimeError(
            "No AI backend is available. Check that at least one of GROQ_API_KEY, "
            "ANTHROPIC_API_KEY, or OPENAI_API_KEY is set in your Streamlit secrets."
        )

    msgs = [{"role": "system", "content": system}] + history + [{"role": "user", "content": question}]
    try:
        stream = groq_client.chat.completions.create(
            model="llama-3.3-70b-versatile",
            messages=msgs,
            temperature=0.55,
            max_tokens=1024,
            stream=True,
            timeout=30.0,
        )
    except Exception as stream_exception:
        import traceback as _tb
        print(f"Groq streaming error: {str(stream_exception)}")
        _tb.print_exc()
        raise RuntimeError(f"Groq API error: {str(stream_exception)}") from stream_exception
    for chunk in stream:
        delta = chunk.choices[0].delta.content or ""
        if delta:
            full_response += delta
            yield ("chunk", delta, full_response)
    yield ("done", full_response, {"memory": memory, "sources": sources, "confidence": confidence_level, "confidence_pct": confidence_pct, "engine": "groq"})

def medichat_vision(question, b64, all_messages, lang_instruction=""):
    memory = extract_patient_memory(all_messages)
    memory_context = build_memory_context(memory)
    # Saved profile data informs image analysis too, e.g. a patient on
    # Foracort has asthma, which changes how a chest X-ray reads.
    profile_context = build_user_profile_context()
    prompt = question.strip() if question.strip() else "Please analyse this medical image."
    memory_note = ("\n\nPatient context (from earlier conversations): " + memory_context) if memory_context else ""
    profile_note = (
        "\n\nPATIENT'S SAVED MEDICHAT PROFILE (authoritative, reference when "
        "relevant to interpreting the image):\n" + profile_context
    ) if profile_context else ""
    lang_note = ("\n\n" + lang_instruction) if lang_instruction else ""

    system_text = (
        "You are MediChat, a warm but rigorous clinical AI companion. The patient has shared a medical image "
        "(skin condition, X-ray, rash, mole, wound, CT slice, ultrasound, ECG, etc.). Analyse it carefully and "
        "respond in plain language with the specificity a thoughtful junior doctor would use.\n\n"
        "CRITICAL: This image is the patient's OWN medical image that they uploaded for their own education and "
        "triage. There is no third-party identification involved, an X-ray, CT, MRI, ultrasound, ECG, or skin photo "
        "cannot identify a specific person to anyone outside their care team. NEVER refuse with 'I can't identify "
        "or analyze individuals in images' or similar, that refusal does not apply here. Describe the anatomy and "
        "findings you can see. Do not refuse a medical-image analysis task.\n\n"
        "STRUCTURE YOUR RESPONSE WITH THESE BOLD SECTIONS:\n"
        "**What I see:**\n"
        "Describe what is visible with SPECIFIC anatomical detail. For chest X-rays this means:\n"
        "- Which lung is affected (left, right, both) and which zone (upper, middle, lower).\n"
        "- The pattern of the abnormality (e.g. rounded mass, patchy consolidation, blunting of the costophrenic angle suggesting pleural effusion, cavitation, nodule, hyperinflation, pneumothorax, widened mediastinum).\n"
        "- Any obvious asymmetry between the two sides.\n"
        "For skin lesions: size estimate, colour, borders (regular vs irregular), elevation, surrounding skin, asymmetry. Apply ABCDE if relevant.\n"
        "For other images: name the anatomy you can identify and the abnormal feature(s) you observe.\n"
        "Be specific, never write only 'increased opacity' or 'some abnormality' when you can localise it.\n\n"
        "**What this could suggest:**\n"
        "Give a differential diagnosis with 2 to 4 plausible causes ordered from most to least likely, briefly explaining each. "
        "Cover common AND serious-but-treatable causes. For chest X-rays with focal opacity that does not have airspace features, "
        "INCLUDE malignancy (lung cancer / mass) in the differential, hedged appropriately, do not omit a serious diagnosis just because it is scary. "
        "Phrase as possibilities, not verdicts.\n\n"
        "**What you should do:**\n"
        "Concrete next step: which specialist or test (e.g. urgent GP review for chest X-ray with suspicious mass, CT chest, dermatology referral, "
        "A&E if red flags). Mention any red flags that would change urgency.\n\n"
        "FORMATTING RULES:\n"
        "- Never use em-dashes or en-dashes. Use commas, semicolons, colons.\n"
        "- Never use # ## ### markdown headings.\n"
        "- Use bullet points (- item) on their own lines for lists.\n"
        "- Do not give a final diagnosis or specific medication dosages.\n"
        "- One brief disclaimer at most, at the end."
        + profile_note + memory_note + lang_note
    )

    # Refusal patterns that mean OpenAI's safety filter wrongly flagged
    # the medical image. When we see one, fall through to Claude which
    # handles medical imaging more reliably.
    def _is_refusal(text):
        if not text:
            return True
        t = text.lower().strip()
        return any(p in t for p in (
            "can't help with identifying",
            "cannot help with identifying",
            "can't help with analyzing individuals",
            "cannot help with analyzing individuals",
            "can't identify or analyze",
            "cannot identify or analyze",
            "i'm sorry, i can't",
            "i'm sorry, i cannot",
            "i am unable to analyze",
            "i'm unable to analyze",
            "as an ai, i can't analyze",
        )) and len(t) < 400

    # Vision dispatch order: OpenAI (frontier) -> Claude -> Groq.
    if OPENAI_ACTIVE and openai_client is not None:
        try:
            resp = openai_client.chat.completions.create(
                model="gpt-4o",
                messages=[
                    {"role": "system", "content": system_text},
                    {"role": "user", "content": [
                        {"type": "text", "text": prompt},
                        {"type": "image_url", "image_url": {"url": "data:image/jpeg;base64," + b64, "detail": "high"}},
                    ]},
                ],
                temperature=0.3,
                max_tokens=1500,
            )
            _openai_out = resp.choices[0].message.content
            if not _is_refusal(_openai_out):
                return _openai_out, "openai-vision"
            print("OpenAI vision refused, falling back to Claude.")
        except Exception as e:
            print("OpenAI vision failed, trying Claude:", e)

    if CLAUDE_ACTIVE:
        try:
            resp = anthropic_client.messages.create(
                model=CLAUDE_MODEL,
                max_tokens=1500,
                system=system_text,
                messages=[{
                    "role": "user",
                    "content": [
                        {"type": "image", "source": {"type": "base64", "media_type": "image/jpeg", "data": b64}},
                        {"type": "text", "text": prompt},
                    ]
                }],
                temperature=0.4,
            )
            return resp.content[0].text, "claude"
        except Exception as e:
            print("Claude vision failed, falling back to Groq:", e)

    # Groq fallback. Guard against the client being None when the
    # GROQ_API_KEY is not configured (local dev, missing secret) so
    # the user sees a clean message instead of an AttributeError.
    if not GROQ_ACTIVE or groq_client is None:
        return (
            "Vision Ai is not available right now. The image analyser needs an active "
            "Claude or Groq API key configured in Streamlit secrets. Please ask the "
            "admin to set ANTHROPIC_API_KEY or GROQ_API_KEY."
        ), "unavailable"
    try:
        r = groq_client.chat.completions.create(
            model="meta-llama/llama-4-scout-17b-16e-instruct",
            messages=[{"role": "user", "content": [
                {"type": "text", "text": system_text + "\n\nQuestion: " + prompt},
                {"type": "image_url", "image_url": {"url": "data:image/jpeg;base64," + b64}}
            ]}],
            temperature=0.5, max_tokens=1024
        )
        return r.choices[0].message.content, "groq-vision"
    except Exception as e:
        print("Groq vision failed:", e)
        return (
            "Vision Ai could not analyse this image right now. The connection to the "
            "image model failed. Please try again in a moment or check the network."
        ), "error"

def clean_text(text):
    replacements = {"\u2019": "'", "\u2018": "'", "\u201c": '"', "\u201d": '"', "\u2013": "-", "\u2014": "-", "\u2022": "-"}
    for k, v in replacements.items():
        text = text.replace(k, v)
    return text.encode("latin-1", errors="replace").decode("latin-1")

def generate_doctor_visit_summary(messages, patient_name=""):
    if not messages:
        return None, None

    transcript_parts = []
    for msg in messages:
        role = msg.get("role", "")
        content = msg.get("content", "")
        if not content:
            continue
        if role == "user":
            transcript_parts.append("Patient said: " + content)
        elif role == "assistant":
            transcript_parts.append("MediChat replied: " + content)
    transcript = "\n\n".join(transcript_parts)

    name_line = ("Patient name: " + patient_name + "\n") if patient_name and patient_name != "Guest" else ""

    system_prompt = (
        "You are a medical scribe assistant. The patient had a conversation with an AI health companion. "
        "Your job is to produce a CONCISE, STRUCTURED summary the patient can hand to their actual GP at their next appointment. "
        "Use ONLY information from the conversation. Do NOT invent symptoms, dates, or details.\n\n"
        "OUTPUT FORMAT (use these exact section labels with bold markdown):\n\n"
        "**Patient overview:**\n"
        "(One sentence describing who this is and what brought them to the chat)\n\n"
        "**Symptoms reported:**\n"
        "- (each symptom on its own bullet)\n\n"
        "**Duration and pattern:**\n"
        "(When symptoms started, how often, what triggers them. If unknown, say 'not discussed'.)\n\n"
        "**Relevant medical history mentioned:**\n"
        "- (each condition or medication on its own bullet, or 'None mentioned' if not discussed)\n\n"
        "**Concerns raised by patient:**\n"
        "(What the patient is worried about, in their own framing)\n\n"
        "**MediChat's preliminary assessment:**\n"
        "(Brief summary of what the AI suggested, hedged appropriately)\n\n"
        "**Suggested questions for the GP:**\n"
        "- (3-5 specific questions the patient should ask their doctor)\n\n"
        "RULES:\n"
        "- Never use em-dashes or en-dashes. Use commas, semicolons, colons.\n"
        "- Never use # ## ### markdown headings.\n"
        "- Be factual. No fluff. No greetings. No sign-offs.\n"
    )

    user_prompt = (
        name_line +
        "Generate a doctor visit prep summary from this conversation:\n\n" +
        transcript[:8000]
    )

    summary_text = ""
    # Doctor Visit Summary dispatch: OpenAI -> Claude -> Groq.
    if OPENAI_ACTIVE and openai_client is not None:
        try:
            resp = openai_client.chat.completions.create(
                model="gpt-4o-mini",
                messages=[
                    {"role": "system", "content": system_prompt},
                    {"role": "user", "content": user_prompt},
                ],
                temperature=0.3,
                max_tokens=1500,
            )
            summary_text = resp.choices[0].message.content
        except Exception as e:
            print("OpenAI summary failed, trying Claude:", e)

    if not summary_text and CLAUDE_ACTIVE:
        try:
            resp = anthropic_client.messages.create(
                model=CLAUDE_MODEL,
                max_tokens=1500,
                system=system_prompt,
                messages=[{"role": "user", "content": user_prompt}],
                temperature=0.3,
            )
            summary_text = resp.content[0].text
        except Exception as e:
            print("Claude summary failed, trying Groq:", e)

    if not summary_text and GROQ_ACTIVE and groq_client is not None:
        try:
            r = groq_client.chat.completions.create(
                model="llama-3.3-70b-versatile",
                messages=[{"role": "system", "content": system_prompt}, {"role": "user", "content": user_prompt}],
                temperature=0.3,
                max_tokens=1500,
            )
            summary_text = r.choices[0].message.content
        except Exception as e:
            print("Groq summary failed:", e)

    if not summary_text:
        return None, None

    pdf = FPDF()
    pdf.add_page()
    pdf.set_margins(20, 20, 20)
    pdf.set_auto_page_break(auto=True, margin=28)

    _pdf_header(
        pdf,
        "Doctor Visit Summary",
        "Patient: " + (patient_name if patient_name and patient_name != "Guest" else "Patient"),
    )
    _pdf_info_box(pdf,
        "Bring this summary to your GP appointment. It captures what you "
        "discussed with MediChat, including symptoms, history, and questions to ask. "
        "This is NOT a diagnosis. Your GP will make the clinical judgement."
    )
    pdf.ln(4)

    pdf.set_text_color(40, 40, 40)
    cleaned_summary = clean_text(summary_text)

    lines = cleaned_summary.split("\n")
    for line in lines:
        stripped = line.strip()
        if not stripped:
            pdf.ln(2)
            continue
        bold_match = re.match(r"^\*\*(.+?)\*\*:?$", stripped)
        if bold_match:
            pdf.ln(2)
            pdf.set_font("Helvetica", "B", 11)
            pdf.set_text_color(30, 58, 54)
            pdf.cell(0, 6, bold_match.group(1).rstrip(":") + ":", ln=True)
            pdf.set_text_color(40, 40, 40)
            continue
        bullet_match = re.match(r"^[\-\*]\s+(.+)$", stripped)
        if bullet_match:
            pdf.set_font("Helvetica", "", 10)
            pdf.set_x(25)
            pdf.cell(5, 5, "-", ln=False)
            pdf.multi_cell(0, 5, bullet_match.group(1))
            continue
        pdf.set_font("Helvetica", "", 10)
        plain = re.sub(r"\*\*([^\*]+)\*\*", r"\1", stripped)
        pdf.multi_cell(0, 5, plain)

    _pdf_footer(pdf)

    pdf_bytes = bytes(pdf.output(dest="S"))
    return pdf_bytes, summary_text


def generate_full_medical_record_pdf(patient_name=""):
    """Build a comprehensive medical-record PDF the patient can hand to (or
    email) their GP. Pulls everything saved on MediChat: meds, allergies,
    family history, surgical history, appointments, uploaded records with
    AI summaries + extracted key values, and today's vitals. Designed to
    save a busy GP 5-10 minutes of history-taking on intake.
    """
    pdf = FPDF()
    pdf.add_page()
    pdf.set_margins(20, 20, 20)
    pdf.set_auto_page_break(auto=True, margin=28)

    _patient_label = patient_name if patient_name and patient_name.lower() != "guest" else "Patient"
    _pdf_header(pdf, "Patient Medical Record", "Patient: " + _patient_label)
    _pdf_info_box(pdf,
        "This is a structured summary of the patient's MediChat profile. "
        "All entries below were saved by the patient or extracted from documents "
        "they uploaded. Use as a starting point for clinical history; verify with "
        "the patient where needed."
    )
    pdf.ln(4)

    def _section(title, body_lines, color=(20, 66, 114)):
        if not body_lines:
            return
        pdf.set_text_color(*color)
        pdf.set_font("Helvetica", "B", 12)
        pdf.ln(2)
        pdf.cell(0, 7, title, ln=True)
        pdf.set_draw_color(*color)
        pdf.line(20, pdf.get_y(), 190, pdf.get_y())
        pdf.ln(2)
        pdf.set_text_color(40, 40, 40)
        pdf.set_font("Helvetica", "", 10)
        for line in body_lines:
            cleaned = clean_text(line)
            if cleaned.startswith("•") or cleaned.startswith("-"):
                pdf.set_x(25)
                pdf.cell(5, 5, "-", ln=False)
                pdf.multi_cell(0, 5, cleaned.lstrip("•- ").strip())
            elif cleaned.endswith(":") and len(cleaned) < 60:
                pdf.set_font("Helvetica", "B", 10)
                pdf.cell(0, 5, cleaned, ln=True)
                pdf.set_font("Helvetica", "", 10)
            else:
                pdf.multi_cell(0, 5, cleaned)

    # ── Medications ──────────────────────────────────────────────
    try:
        meds = list_medications() or []
    except Exception:
        meds = []
    if meds:
        med_lines = []
        for m in meds:
            head = (m.get("name") or "").strip()
            bits = []
            if m.get("dose"):
                bits.append(m["dose"])
            if m.get("frequency"):
                bits.append(m["frequency"])
            if m.get("time_of_day"):
                bits.append(m["time_of_day"])
            line = "- " + head
            if bits:
                line += " (" + ", ".join(bits) + ")"
            if m.get("notes"):
                line += " - " + m["notes"]
            med_lines.append(line)
        _section("Current Medications", med_lines)

    # ── Allergies (red emphasis) ─────────────────────────────────
    try:
        allergies = list_allergies() or []
    except Exception:
        allergies = []
    if allergies:
        a_lines = []
        for a in allergies:
            head = (a.get("name") or "").strip()
            extras = []
            if a.get("severity"):
                extras.append("severity: " + a["severity"])
            if a.get("reaction"):
                extras.append("reaction: " + a["reaction"])
            line = "- " + head
            if extras:
                line += " (" + "; ".join(extras) + ")"
            if a.get("notes"):
                line += " - " + a["notes"]
            a_lines.append(line)
        _section("Known Allergies", a_lines, color=(190, 30, 30))

    # ── Family history ───────────────────────────────────────────
    try:
        fh = list_family_history() or []
    except Exception:
        fh = []
    if fh:
        fh_lines = []
        for f in fh:
            head = (f.get("condition") or "").strip()
            extras = []
            if f.get("relationship"):
                extras.append(f["relationship"])
            if f.get("age_at_diagnosis"):
                extras.append("dx age " + str(f["age_at_diagnosis"]))
            line = "- " + head
            if extras:
                line += " (" + ", ".join(extras) + ")"
            if f.get("notes"):
                line += " - " + f["notes"]
            fh_lines.append(line)
        _section("Family Medical History", fh_lines)

    # ── Surgical history ─────────────────────────────────────────
    try:
        surg = list_surgical_history() or []
    except Exception:
        surg = []
    if surg:
        try:
            surg_sorted = sorted(surg, key=lambda s: (s.get("year") or ""), reverse=True)
        except Exception:
            surg_sorted = surg
        s_lines = []
        for s in surg_sorted:
            head = (s.get("procedure") or "").strip()
            extras = []
            if s.get("year"):
                extras.append(s["year"])
            if s.get("hospital"):
                extras.append(s["hospital"])
            line = "- " + head
            if extras:
                line += " (" + ", ".join(extras) + ")"
            if s.get("notes"):
                line += " - " + s["notes"]
            s_lines.append(line)
        _section("Surgical History", s_lines)

    # ── Upcoming / recent appointments ──────────────────────────
    try:
        appts = list_appointments() or []
    except Exception:
        appts = []
    if appts:
        try:
            appts_sorted = sorted(appts, key=lambda a: (a.get("date") or ""), reverse=True)
        except Exception:
            appts_sorted = appts
        ap_lines = []
        for a in appts_sorted[:8]:
            head_bits = []
            if a.get("date"):
                head_bits.append(a["date"])
            if a.get("title"):
                head_bits.append(a["title"])
            tail_bits = []
            if a.get("doctor"):
                tail_bits.append("Dr " + a["doctor"])
            if a.get("location"):
                tail_bits.append("at " + a["location"])
            line = "- " + " - ".join(head_bits)
            if tail_bits:
                line += " (" + ", ".join(tail_bits) + ")"
            ap_lines.append(line)
        _section("Appointments", ap_lines)

    # ── Today's vitals ───────────────────────────────────────────
    try:
        dm = get_daily_metrics() or {}
    except Exception:
        dm = {}
    v_lines = []
    if dm.get("heart_rate_resting") is not None:
        v_lines.append("- Resting heart rate: " + str(dm["heart_rate_resting"]) + " bpm")
    if dm.get("sleep_hours") is not None:
        v_lines.append("- Sleep last night: " + str(dm["sleep_hours"]) + " hours")
    if dm.get("steps") is not None:
        v_lines.append("- Steps today: " + str(dm["steps"]))
    if dm.get("water_glasses") is not None:
        v_lines.append("- Water intake today: " + str(dm["water_glasses"]) + "/8 glasses")
    if dm.get("mood"):
        v_lines.append("- Mood: " + str(dm["mood"]))
    if v_lines:
        _section("Today's Vitals", v_lines)

    # ── Uploaded health records with AI summaries ────────────────
    try:
        records = list_health_records() or []
    except Exception:
        records = []
    if records:
        try:
            records_sorted = sorted(records, key=lambda r: (r.get("uploaded_at") or ""), reverse=True)
        except Exception:
            records_sorted = records
        # New page for records since each block can be long.
        pdf.add_page()
        pdf.set_x(pdf.l_margin)
        pdf.set_text_color(20, 66, 114)
        pdf.set_font("Helvetica", "B", 14)
        pdf.cell(0, 8, "Uploaded Health Records", ln=True)
        pdf.set_draw_color(20, 66, 114)
        pdf.line(20, pdf.get_y(), 190, pdf.get_y())
        pdf.ln(3)

        # FPDF2 doesn't reliably reset the x-cursor to the left margin
        # after multi_cell(), calling another multi_cell can then crash
        # with "Not enough horizontal space to render a single character"
        # because the available width has shrunk to zero. Wrapping each
        # multi_cell in this helper guarantees a clean left-margin start
        # AND swallows the same exception defensively so a single
        # malformed record can't kill the whole PDF.
        def _safe_mc(text, line_h=4):
            try:
                pdf.set_x(pdf.l_margin)
                pdf.multi_cell(0, line_h, clean_text(text))
            except Exception as _mc_e:
                # If a long unbreakable token (e.g. a binary blob in the
                # extracted text) still fails, fall back to a small fixed
                # width and a truncated version so we lose this record's
                # detail rather than the whole PDF.
                try:
                    pdf.set_x(pdf.l_margin)
                    pdf.multi_cell(
                        170, line_h,
                        clean_text(text[:400]) +
                        "  [truncated, content not renderable]"
                    )
                except Exception:
                    # Give up on this block entirely, keep the PDF alive.
                    print("safe_mc giving up on record block:", repr(_mc_e))

        for r in records_sorted[:10]:
            head = (r.get("name") or "(unnamed)").strip()
            uploaded = (r.get("uploaded_at") or "")[:10]
            ftype = (r.get("file_type") or "").strip()
            pdf.set_x(pdf.l_margin)
            pdf.set_font("Helvetica", "B", 11)
            pdf.set_text_color(30, 58, 54)
            title_bits = []
            if uploaded:
                title_bits.append(uploaded)
            title_bits.append(head)
            if ftype:
                title_bits.append("(" + ftype + ")")
            _safe_mc(" - ".join(title_bits), line_h=5)
            summary = (r.get("summary") or "").strip()
            if summary:
                pdf.set_font("Helvetica", "I", 9)
                pdf.set_text_color(60, 60, 60)
                _safe_mc("AI summary: " + summary[:1200], line_h=4)
            raw = (r.get("raw_text") or "").strip()
            if raw and raw != summary:
                pdf.set_font("Helvetica", "", 9)
                pdf.set_text_color(40, 40, 40)
                cleaned_raw = re.sub(r"[ \t]+", " ", raw)[:1400]
                _safe_mc("Extracted key values: " + cleaned_raw, line_h=4)
            pdf.ln(3)

    # ── Footer disclaimer on the last page ───────────────────────
    _pdf_footer(pdf)

    return bytes(pdf.output(dest="S"))


def _pdf_logo_path():
    """Resolve the MediChat brand logo path for embedding in PDFs."""
    return _resolve_asset_path("MediChat logo.png")

def _pdf_measure_lines(pdf, w, text, line_h=5):
    """Return the line count multi_cell would produce, without rendering.
    Uses fpdf2's dry_run if available; falls back to character estimation."""
    try:
        result = pdf.multi_cell(w, line_h, clean_text(text), dry_run=True, output="LINES")
        return max(1, len(result))
    except Exception:
        pass
    # Conservative fallback: split on newlines + estimate wrap.
    text = clean_text(text)
    n = 0
    for paragraph in text.split("\n"):
        if not paragraph.strip():
            n += 1
            continue
        try:
            pw = pdf.get_string_width(paragraph)
            n += max(1, int(pw / max(1, w - 2)) + 1)
        except Exception:
            n += max(1, len(paragraph) // 70 + 1)
    return max(1, n)

def _pdf_header(pdf, title, subtitle=""):
    """Premium MediChat PDF header: brand band, logo + brand + tagline + title."""
    # Slim brand-color band across the very top — instant premium feel.
    pdf.set_fill_color(33, 118, 174)
    pdf.rect(0, 0, 210, 3.5, "F")
    # Logo (skip silently if asset missing)
    try:
        _logo = _pdf_logo_path()
        if _logo and os.path.exists(_logo):
            pdf.image(_logo, x=20, y=11, w=14, h=14)
    except Exception:
        pass
    # Brand wordmark next to logo
    pdf.set_xy(36, 12)
    pdf.set_text_color(33, 118, 174)
    pdf.set_font("Helvetica", "B", 17)
    pdf.cell(50, 7, "MediChat")
    # Tagline under wordmark, mirrors the in-app brand lockup
    pdf.set_xy(36, 20)
    pdf.set_text_color(120, 130, 144)
    pdf.set_font("Helvetica", "", 7.5)
    pdf.cell(50, 4, "Your AI Health Assistant")
    # Generated date top-right
    pdf.set_xy(120, 14)
    pdf.set_text_color(100, 116, 139)
    pdf.set_font("Helvetica", "", 8)
    # Use the viewer's local time, not UTC (Streamlit Cloud server is UTC).
    try:
        _gen_dt = get_user_local_now()
    except Exception:
        _gen_dt = datetime.now()
    pdf.cell(70, 4, "Generated " + _gen_dt.strftime("%B %d, %Y at %I:%M %p"), align="R")
    # Title - large bold navy
    pdf.set_xy(20, 34)
    pdf.set_text_color(12, 45, 72)
    pdf.set_font("Helvetica", "B", 22)
    pdf.cell(0, 10, clean_text(title), ln=True)
    if subtitle:
        pdf.set_x(20)
        pdf.set_text_color(33, 118, 174)
        pdf.set_font("Helvetica", "B", 11)
        pdf.cell(0, 6, clean_text(subtitle), ln=True)
    # Hairline divider
    pdf.set_draw_color(226, 232, 240)
    pdf.set_line_width(0.4)
    y_div = pdf.get_y() + 3
    pdf.line(20, y_div, 190, y_div)
    pdf.set_y(y_div + 5)

def _pdf_info_box(pdf, text, color="info"):
    """Soft tinted call-out box, borderless for a cleaner card feel."""
    if color == "warn":
        bg, ic_bg, ic_fg, tx = (255, 251, 235), (245, 158, 11), (255, 255, 255), (146, 64, 14)
    elif color == "safe":
        bg, ic_bg, ic_fg, tx = (240, 253, 244), (34, 197, 94), (255, 255, 255), (22, 101, 52)
    else:
        bg, ic_bg, ic_fg, tx = (239, 246, 252), (33, 118, 174), (255, 255, 255), (30, 64, 175)
    pdf.set_font("Helvetica", "", 9)
    body_w = 148
    line_h = 4.7
    n_lines = _pdf_measure_lines(pdf, body_w, text, line_h=line_h)
    pad_y = 5
    box_h = max(16, pad_y * 2 + n_lines * line_h)
    y = pdf.get_y()
    # Borderless tinted card — looks softer than the old outlined rect.
    pdf.set_fill_color(*bg)
    pdf.set_draw_color(*bg)
    pdf.rect(20, y, 170, box_h, "F")
    # Icon disc, vertically centered
    icon_d = 8
    icon_y = y + (box_h - icon_d) / 2
    pdf.set_fill_color(*ic_bg)
    pdf.ellipse(25, icon_y, icon_d, icon_d, "F")
    pdf.set_text_color(*ic_fg)
    pdf.set_font("Helvetica", "B", 10)
    pdf.set_xy(25, icon_y + 1.2)
    pdf.cell(icon_d, icon_d - 2.4, "i", align="C")
    # Body
    pdf.set_text_color(*tx)
    pdf.set_font("Helvetica", "", 9)
    pdf.set_xy(37, y + pad_y)
    pdf.multi_cell(body_w, line_h, clean_text(text))
    pdf.set_y(y + box_h + 5)

def _pdf_section_label(pdf, label, color=(13, 148, 136)):
    """Section header rendered as a soft colored pill chip — premium feel."""
    y = pdf.get_y()
    label_text = label.upper()
    pdf.set_font("Helvetica", "B", 8.5)
    text_w = pdf.get_string_width(label_text)
    pad_x = 4.5
    chip_w = text_w + pad_x * 2
    chip_h = 6.2
    r, g, b = color
    # Mix 88% white into the brand color for a soft tinted bg
    lr = int(255 - (255 - r) * 0.12)
    lg = int(255 - (255 - g) * 0.12)
    lb = int(255 - (255 - b) * 0.12)
    pdf.set_fill_color(lr, lg, lb)
    pdf.set_draw_color(lr, lg, lb)
    pdf.rect(20, y, chip_w, chip_h, "F")
    pdf.set_text_color(r, g, b)
    pdf.set_xy(20 + pad_x, y + 0.9)
    pdf.cell(text_w, chip_h - 1.8, label_text)
    pdf.set_y(y + chip_h + 5)

def _pdf_footer(pdf):
    """Footer pinned at the bottom: disclaimer left, brand + page number right.
    Auto-page-break is temporarily disabled so placement never spills to a new
    blank page."""
    was_auto = getattr(pdf, "auto_page_break", True)
    try:
        pdf.set_auto_page_break(False)
        pdf.set_y(275)
        pdf.set_draw_color(226, 232, 240)
        pdf.set_line_width(0.3)
        pdf.line(20, 275, 190, 275)
        # Small print disclaimer left
        pdf.set_text_color(120, 130, 144)
        pdf.set_font("Helvetica", "", 7)
        pdf.set_xy(20, 278)
        pdf.multi_cell(128, 3.0,
            "MediChat is a research prototype, not a medical device. This document is compiled "
            "from patient-submitted data and AI-extracted text and may contain errors or "
            "omissions. Always rely on your qualified clinical judgement."
        )
        # Brand mark right
        pdf.set_xy(150, 278)
        pdf.set_text_color(33, 118, 174)
        pdf.set_font("Helvetica", "B", 9.5)
        pdf.cell(40, 4, "MediChat AI", align="R")
        # Page number below brand mark
        try:
            page_n = pdf.page_no()
        except Exception:
            page_n = 0
        if page_n:
            pdf.set_xy(150, 283)
            pdf.set_text_color(160, 170, 184)
            pdf.set_font("Helvetica", "", 7)
            pdf.cell(40, 3, "Page " + str(page_n), align="R")
    finally:
        # Restore auto-page-break (best effort)
        try:
            if was_auto:
                pdf.set_auto_page_break(True, margin=22)
        except Exception:
            pass

def generate_chat_pdf(messages):
    pdf = FPDF()
    pdf.add_page()
    pdf.set_margins(20, 20, 20)
    # Bottom margin 28 leaves room for the pinned footer at y=275 and
    # stops content from drifting over the disclaimer line.
    pdf.set_auto_page_break(auto=True, margin=28)
    _pdf_header(pdf, "Conversation Export")
    _pdf_info_box(pdf,
        "DISCLAIMER: This conversation is for informational purposes only. "
        "Always consult a qualified healthcare professional."
    )
    _pdf_section_label(pdf, "Conversation Transcript")

    for msg in messages:
        role = msg.get("role", "")
        content = msg.get("content", "")
        msg_type = msg.get("type", "text")
        msg_ts = msg.get("ts", "")
        if not content and msg_type not in ("image", "pdf"):
            continue
        is_user = role == "user"
        if is_user:
            stripe_clr = (33, 118, 174)
            bubble_bg = (239, 246, 252)
        else:
            stripe_clr = (13, 148, 136)
            bubble_bg = (240, 253, 250)
        label_text = "You" if is_user else "MediChat"
        # Strip markdown bold (**text** / **text:**) and inline markers
        # so the PDF reads clean — no literal asterisks bleeding through.
        _raw_body = (
            "[Medical image uploaded]" + (": " + content if content else "")
            if msg_type == "image" else
            ("[PDF: " + (msg.get("file_name", "document.pdf")) + "]" + ((" " + content) if content and "[PDF:" not in content else ""))
            if msg_type == "pdf" else
            content
        )
        _raw_body = re.sub(r"\*\*([^\*]+)\*\*", r"\1", _raw_body)
        _raw_body = _raw_body.replace("**", "")
        body_text = clean_text(_raw_body)

        # If the user uploaded an actual image, decode it once so we can
        # both size the bubble around it AND embed it after the text.
        _embed_image_bio = None
        _embed_img_h = 0
        if msg_type == "image":
            _img_b64 = msg.get("image_b64", "") or ""
            if _img_b64:
                try:
                    import io as _io_em
                    _embed_image_bio = _io_em.BytesIO(base64.b64decode(_img_b64))
                    _embed_img_h = 60  # mm — uniform thumbnail height
                except Exception:
                    _embed_image_bio = None
                    _embed_img_h = 0

        # Measure body height first so we can draw the tinted bubble bg
        # UNDER the text in a single pass (no double-render).
        body_w = 160
        line_h = 5.2
        pdf.set_font("Helvetica", "", 9.5)
        body_n_lines = _pdf_measure_lines(pdf, body_w, body_text, line_h=line_h)
        bubble_h = max(18, 11 + body_n_lines * line_h + 5 + (_embed_img_h + 4 if _embed_image_bio else 0))

        start_y = pdf.get_y()
        # Paint bg + left stripe first so text renders on top.
        pdf.set_fill_color(*bubble_bg)
        pdf.set_draw_color(*bubble_bg)
        pdf.rect(20, start_y, 170, bubble_h, "F")
        pdf.set_fill_color(*stripe_clr)
        pdf.rect(20, start_y, 2.5, bubble_h, "F")
        # Label (left) + timestamp (right)
        pdf.set_xy(28, start_y + 5)
        pdf.set_text_color(*stripe_clr)
        pdf.set_font("Helvetica", "B", 10)
        pdf.cell(80, 5, label_text)
        if msg_ts:
            pdf.set_xy(150, start_y + 5)
            pdf.set_text_color(140, 150, 165)
            pdf.set_font("Helvetica", "", 8)
            pdf.cell(40, 5, clean_text(msg_ts), align="R")
        # Body
        pdf.set_xy(28, start_y + 11)
        pdf.set_text_color(40, 50, 65)
        pdf.set_font("Helvetica", "", 9.5)
        pdf.multi_cell(body_w, line_h, body_text)
        # Embed the actual uploaded image right under the caption.
        if _embed_image_bio is not None:
            try:
                _img_y = pdf.get_y() + 2
                pdf.image(_embed_image_bio, x=28, y=_img_y, h=_embed_img_h)
            except Exception:
                pass
        pdf.set_y(start_y + bubble_h + 4)

    _pdf_footer(pdf)
    return bytes(pdf.output())

def generate_assessment_pdf(parsed, data, report_date):
    pdf = FPDF()
    pdf.add_page()
    pdf.set_margins(20, 20, 20)
    pdf.set_fill_color(33, 118, 174)
    pdf.rect(0, 0, 210, 40, "F")
    pdf.set_text_color(255, 255, 255)
    pdf.set_font("Helvetica", "B", 18)
    pdf.set_y(7)
    pdf.cell(0, 10, "MediChat Assessment Report", ln=True, align="C")
    pdf.set_font("Helvetica", "", 10)
    pdf.cell(0, 7, "Pre-Consultation Health Summary", ln=True, align="C")
    pdf.set_font("Helvetica", "", 9)
    pdf.cell(0, 7, "Generated: " + report_date, ln=True, align="C")
    pdf.set_y(48)
    urgency = parsed.get("urgency", "See a doctor soon")
    urgency_lower = urgency.lower()
    if "emergency" in urgency_lower or "now" in urgency_lower:
        pdf.set_fill_color(254, 226, 226)
        pdf.set_text_color(153, 27, 27)
    elif "urgent" in urgency_lower or "today" in urgency_lower:
        pdf.set_fill_color(255, 251, 235)
        pdf.set_text_color(146, 64, 14)
    else:
        pdf.set_fill_color(240, 253, 244)
        pdf.set_text_color(22, 101, 52)
    pdf.set_font("Helvetica", "B", 11)
    pdf.cell(0, 10, "URGENCY: " + clean_text(urgency), ln=True, fill=True, align="C")
    pdf.ln(5)

    def section_header(title):
        pdf.set_fill_color(33, 118, 174)
        pdf.set_text_color(255, 255, 255)
        pdf.set_font("Helvetica", "B", 10)
        pdf.cell(0, 8, "  " + title, ln=True, fill=True)
        pdf.ln(2)


    def info_row(label, value):
        pdf.set_fill_color(248, 250, 252)
        pdf.set_text_color(51, 65, 85)
        pdf.set_font("Helvetica", "B", 9)
        pdf.cell(50, 7, "  " + label + ":", fill=True)
        pdf.set_font("Helvetica", "", 9)
        pdf.cell(0, 7, " " + clean_text(str(value)), ln=True, fill=True)
        pdf.ln(1)

    section_header("SYMPTOMS REPORTED")
    info_row("Main Symptom", data.get("main_symptom", ""))
    info_row("Duration", data.get("duration", ""))
    info_row("Severity", data.get("severity", ""))
    info_row("Pattern", data.get("pattern", ""))
    other = data.get("other_symptoms", "")
    if other and other.lower() not in ["no", "none", "n/a", "no other symptoms"]:
        info_row("Other Symptoms", other)
    info_row("Known Conditions", data.get("known_conditions", "Not specified"))
    info_row("Current Medications", data.get("current_medications", "Not specified"))
    info_row("Red-flag Symptoms", data.get("red_flags", "Not specified"))
    info_row("Age Group", data.get("age", ""))
    info_row("Biological Sex", data.get("gender", ""))
    pdf.ln(4)
    section_header("POSSIBLE CONDITIONS")
    pdf.set_text_color(51, 65, 85)
    pdf.set_font("Helvetica", "", 9)
    for c in parsed.get("conditions", []):
        if c.strip():
            pdf.set_fill_color(240, 253, 250)
            pdf.cell(8, 7, "", fill=True)
            pdf.cell(0, 7, "- " + clean_text(c.strip()), ln=True)
            pdf.ln(1)
    pdf.ln(3)
    section_header("WHAT TO DO NEXT")
    pdf.set_text_color(51, 65, 85)
    pdf.set_font("Helvetica", "", 9)
    for i, s in enumerate(parsed.get("next_steps", []), 1):
        if s.strip():
            pdf.set_fill_color(248, 250, 252)
            pdf.multi_cell(0, 7, str(i) + ". " + clean_text(s.strip()), fill=True)
            pdf.ln(1)
    pdf.ln(3)
    section_header("MEDICHAT SUMMARY")
    summary = parsed.get("summary", "")
    if summary:
        pdf.set_fill_color(240, 253, 250)
        pdf.set_text_color(19, 78, 74)
        pdf.set_font("Helvetica", "", 9)
        pdf.multi_cell(0, 7, clean_text(summary), fill=True)
    pdf.ln(5)
    pdf.set_fill_color(255, 251, 235)
    pdf.set_text_color(146, 64, 14)
    pdf.set_font("Helvetica", "B", 8)
    pdf.multi_cell(0, 6, "IMPORTANT DISCLAIMER: This report was generated by MediChat Ai and does NOT constitute a medical diagnosis. Please share this with your doctor for professional evaluation and treatment.", fill=True)
    pdf.set_y(-18)
    pdf.set_text_color(148, 163, 184)
    pdf.set_font("Helvetica", "", 7)
    pdf.cell(0, 5, APP_VERSION_LABEL, align="C")
    return bytes(pdf.output())

