# Selection-clear: CSS alone keeps losing the specificity battle against
# Streamlit's Base Web checkbox / radio component styles, so any accidental
# drag-select or persisted text selection on a label/button shows the dark
# purple browser highlight. This injects a JS listener on the parent doc
# that immediately calls getSelection().removeAllRanges() whenever the
# selection lands inside non-content UI chrome (labels, buttons, checkboxes,
# headings, sidebar nav, page hero text). Content areas (chat bubbles, AI
# summaries, report text) are NOT cleared, copy still works there.
try:
    import streamlit.components.v1 as _selclr_components
    _selclr_components.html(
        """
        <script>
        (function() {
            try {
                const win = window.parent;
                const doc = win.document;
                if (win.__medichatSelectionClearV1) return;
                win.__medichatSelectionClearV1 = true;

                // Clear any selection inherited from before this script loaded
                try { win.getSelection().removeAllRanges(); } catch (e) {}

                const NON_SELECTABLE_SELECTOR = [
                    'label',
                    'button',
                    '[data-baseweb="checkbox"]',
                    '[data-baseweb="radio"]',
                    '[data-testid="stWidgetLabel"]',
                    '[data-testid="stCheckbox"]',
                    '[data-testid="stRadio"]',
                    '[data-testid="stForm"] label',
                    '[data-testid="stSidebar"] [data-testid="stMarkdown"]',
                    '.stButton',
                    '.stFormSubmitButton',
                    '.md-page-hero',
                    '.md-page-hero-title',
                    '.assessment-title',
                    '.assessment-subtitle',
                    'h1', 'h2', 'h3', 'h4', 'h5', 'h6'
                ].join(', ');

                function isInsideNonSelectable(node) {
                    if (!node) return false;
                    let el = node.nodeType === 3 ? node.parentElement : node;
                    if (!el) return false;
                    return !!el.closest(NON_SELECTABLE_SELECTOR);
                }

                doc.addEventListener('selectionchange', function() {
                    try {
                        const sel = win.getSelection();
                        if (!sel || sel.rangeCount === 0) return;
                        const range = sel.getRangeAt(0);
                        if (isInsideNonSelectable(range.startContainer) ||
                            isInsideNonSelectable(range.endContainer)) {
                            sel.removeAllRanges();
                        }
                    } catch (e) { /* swallow */ }
                });

                // Also clear on mouseup as a safety net for browsers that
                // don't fire selectionchange reliably during fast drags.
                doc.addEventListener('mouseup', function(ev) {
                    try {
                        if (isInsideNonSelectable(ev.target)) {
                            const sel = win.getSelection();
                            if (sel) sel.removeAllRanges();
                        }
                    } catch (e) {}
                });

                console.log('[MediChat] selection-clear V1 installed');
            } catch (e) { console.error('[MediChat] selection-clear setup failed:', e); }
        })();
        </script>
        """,
        height=0,
    )
except Exception:
    pass


# ── Instant nav-click transition (snappy feel, hides rerun lag) ──────
# Streamlit's full-page rerun takes ~500-1000ms during nav clicks. The
# browser sees the OLD page until the new content arrives, which feels
# laggy. This script listens for nav button clicks and INSTANTLY hides
# the main content + shows a soft brand-color spinner so the user sees
# immediate feedback. A MutationObserver clears the hidden state the
# moment the new page DOM is reconciled in. Result: click → blank +
# spinner → new page fades in. Same total time, but the click feels
# responsive instead of frozen.
try:
    import streamlit.components.v1 as _navfx_components
    _navfx_components.html(
        """
        <script>
        (function() {
            try {
                const win = window.parent;
                const doc = win.document;
                if (win.__medichatNavTransitionV1) return;
                win.__medichatNavTransitionV1 = true;

                const style = doc.createElement('style');
                style.textContent = `
                    body[data-medichat-navigating="true"] [data-testid="stMainBlockContainer"] {
                        opacity: 0 !important;
                        pointer-events: none !important;
                        transition: none !important;
                    }
                    body[data-medichat-navigating="true"] [data-testid="stMain"]::after {
                        content: '';
                        position: fixed;
                        top: 50%;
                        left: calc(50% + 130px);
                        width: 26px;
                        height: 26px;
                        margin: -13px 0 0 -13px;
                        border-radius: 50%;
                        border: 2.5px solid rgba(33, 118, 174, 0.18);
                        border-top-color: #2176ae;
                        animation: mdNavSpin 0.55s linear infinite;
                        z-index: 99999;
                        pointer-events: none;
                    }
                    @keyframes mdNavSpin { to { transform: rotate(360deg); } }
                `;
                doc.head.appendChild(style);

                let clearTimer = null;
                function markNavigating() {
                    doc.body.setAttribute('data-medichat-navigating', 'true');
                    if (clearTimer) clearTimeout(clearTimer);
                    // Safety: never leave the spinner up longer than 4s
                    clearTimer = setTimeout(function() {
                        doc.body.removeAttribute('data-medichat-navigating');
                    }, 4000);
                }
                function clearNavigating() {
                    doc.body.removeAttribute('data-medichat-navigating');
                    if (clearTimer) { clearTimeout(clearTimer); clearTimer = null; }
                }

                // Catch every sidebar nav button click + Smart Action cards
                // + Recent Chats tiles + dashboard tiles. Anything that
                // changes the page should feel instant.
                doc.addEventListener('click', function(e) {
                    const btn = e.target.closest(
                        '[class*="st-key-nav_"], ' +
                        '[class*="st-key-sa_"], ' +
                        '[class*="st-key-qa_"], ' +
                        '[class*="st-key-hist_open_"], ' +
                        '[class*="st-key-hist_new_chat"], ' +
                        '[class*="st-key-hist_back"]'
                    );
                    if (btn) markNavigating();
                }, true);

                // MutationObserver: when the main block container's children
                // change (new page rendered), clear the navigating state on
                // next frame so the new content reveals smoothly.
                const obs = new MutationObserver(function() {
                    if (doc.body.getAttribute('data-medichat-navigating') === 'true') {
                        win.requestAnimationFrame(clearNavigating);
                    }
                });
                function attach() {
                    const main = doc.querySelector('[data-testid="stMain"]');
                    if (main) {
                        obs.observe(main, { childList: true, subtree: true });
                    } else {
                        setTimeout(attach, 100);
                    }
                }
                attach();
            } catch (e) { console.error('[MediChat] nav-transition setup failed:', e); }
        })();
        </script>
        """,
        height=0,
    )
except Exception:
    pass


# ── Mobile app shell (≤ 768px): hide sidebar + bottom tab bar ────────
# Streamlit's sidebar is unusable as mobile navigation: it either overlays
# the whole viewport or leaves a dead gutter. On phone-sized screens we
# remove it entirely (JS-enforced INLINE styles - these reliably beat
# Streamlit's own inline layout styles, unlike stylesheet rules) and give
# the user a native-app-style fixed bottom tab bar instead. Navigation
# goes through the existing ?mode= URL router, preserving the ?s session
# token, so signed-in state survives every tab switch. Desktop (> 768px)
# is completely untouched: every mutation is gated on isMobile() and
# reverted on resize back to desktop widths.
try:
    import streamlit.components.v1 as _mobile_shell_components
    _mobile_shell_components.html(
        """
        <script>
        (function() {
            try {
                const win = window.parent;
                const doc = win.document;

                function isMobile() { return win.innerWidth <= 768; }

                function applyLayout() {
                    const sb = doc.querySelector("section[data-testid='stSidebar']");
                    if (sb) {
                        if (isMobile()) {
                            sb.style.setProperty('display', 'none', 'important');
                        } else {
                            sb.style.removeProperty('display');
                        }
                    }
                    doc.querySelectorAll(
                        "[data-testid='stSidebarCollapsedControl']," +
                        "[data-testid='stSidebarCollapseButton']," +
                        "[data-testid='collapsedControl']"
                    ).forEach(function(el) {
                        if (isMobile()) {
                            el.style.setProperty('display', 'none', 'important');
                        } else {
                            el.style.removeProperty('display');
                        }
                    });
                    const main = doc.querySelector("section[data-testid='stMain']") || doc.querySelector('section.stMain');
                    if (main) {
                        if (isMobile()) {
                            main.style.setProperty('margin-left', '0', 'important');
                            main.style.setProperty('width', '100vw', 'important');
                            main.style.setProperty('max-width', '100vw', 'important');
                        } else {
                            main.style.removeProperty('margin-left');
                            main.style.removeProperty('width');
                            main.style.removeProperty('max-width');
                        }
                    }
                    const blk = doc.querySelector("[data-testid='stMainBlockContainer']");
                    if (blk) {
                        if (isMobile()) {
                            blk.style.setProperty('padding', '0.8rem 0.9rem 96px 0.9rem', 'important');
                            blk.style.setProperty('max-width', '100%', 'important');
                        } else {
                            blk.style.removeProperty('padding');
                            blk.style.removeProperty('max-width');
                        }
                    }
                }

                function currentMode() {
                    try { return new URLSearchParams(win.location.search).get('mode') || ''; }
                    catch (e) { return ''; }
                }
                function hrefFor(mode) {
                    const p = new URLSearchParams(win.location.search);
                    if (mode) { p.set('mode', mode); } else { p.delete('mode'); }
                    p.delete('conv');
                    const q = p.toString();
                    return win.location.pathname + (q ? ('?' + q) : '');
                }

                const TABS = [
                    { mode: '',             icon: 'home',           label: 'Home'    },
                    { mode: 'history',      icon: 'forum',          label: 'Chats'   },
                    { mode: 'assessment',   icon: 'stethoscope',    label: 'Check'   },
                    { mode: 'records',      icon: 'lab_profile',    label: 'Records' },
                    { mode: 'appointments', icon: 'calendar_month', label: 'Appts'   },
                ];

                function buildTabBar() {
                    let bar = doc.getElementById('md-mobile-tabbar');
                    if (!isMobile()) {
                        if (bar) { bar.style.display = 'none'; }
                        return;
                    }
                    if (!bar) {
                        bar = doc.createElement('div');
                        bar.id = 'md-mobile-tabbar';
                        doc.body.appendChild(bar);
                    }
                    bar.style.cssText =
                        'position:fixed;left:0;right:0;bottom:0;z-index:999990;display:flex;' +
                        'background:rgba(255,255,255,0.97);backdrop-filter:blur(14px);' +
                        '-webkit-backdrop-filter:blur(14px);border-top:1px solid #e2e8f0;' +
                        'box-shadow:0 -4px 18px rgba(15,23,42,0.07);' +
                        'padding:6px 4px calc(7px + env(safe-area-inset-bottom)) 4px;';
                    const cur = currentMode();
                    bar.innerHTML = '';
                    TABS.forEach(function(t) {
                        const active = t.mode ? (cur === t.mode) : (cur === '' || cur === 'chat');
                        const a = doc.createElement('a');
                        a.href = hrefFor(t.mode);
                        a.style.cssText =
                            'flex:1;display:flex;flex-direction:column;align-items:center;gap:2px;' +
                            'text-decoration:none;padding:5px 0 3px 0;border-radius:12px;' +
                            'transition:color 0.15s ease;' +
                            (active ? 'color:#4f46e5;' : 'color:#64748b;');
                        a.innerHTML =
                            '<span class="material-symbols-rounded" style="font-size:22px;line-height:1;' +
                            (active ? "font-variation-settings:'FILL' 1, 'wght' 500;" : '') + '">' + t.icon + '</span>' +
                            '<span style="font-size:10px;font-weight:600;letter-spacing:0.02em;">' + t.label + '</span>';
                        bar.appendChild(a);
                    });
                }

                function tick() { applyLayout(); buildTabBar(); }
                tick();
                setTimeout(tick, 300);
                setTimeout(tick, 1000);
                // Interval survives for this script instance's lifetime;
                // when Streamlit reruns and replaces this component iframe,
                // the new instance takes over and the old timers die with
                // the old iframe. Resize listener re-applies instantly on
                // orientation change / window resize.
                setInterval(tick, 1200);
                win.addEventListener('resize', tick);
            } catch (e) { console.error('[MediChat] mobile-shell setup failed:', e); }
        })();
        </script>
        """,
        height=0,
    )
except Exception:
    pass

