    if st.session_state.get("is_authenticated"):
        _pending_count = len(list_pending_partner_invites() or [])
        _link_label = ("Care Circle" + (("  (" + str(_pending_count) + ")") if _pending_count else ""))
        if st.button(_link_label, key="open_partners_dialog", icon=":material/diversity_3:", use_container_width=True):
            st.session_state.show_partners_dialog = True
            st.rerun()

    # Language selector sits immediately above the Privacy & Consent button.
    _lang_keys_top = list(LANGUAGES.keys())
    _current_lang_top = st.session_state.get("selected_language", "English")
    _lang_idx_top = _lang_keys_top.index(_current_lang_top) if _current_lang_top in _lang_keys_top else 0
    st.markdown('<div class="md-lang-selector-anchor"></div>', unsafe_allow_html=True)
    st.selectbox(
        "Language",
        options=_lang_keys_top,
        index=_lang_idx_top,
        key="lang_selector",
        label_visibility="collapsed",
    )
    # Lock the combobox input to read-only so the picker behaves as a
    # tap-to-open button.
    import streamlit.components.v1 as _components_lang
    _components_lang.html(
        """
        <script>
        (function(){
            function lock(){
                try {
                    var doc = window.parent.document;
                    var inputs = doc.querySelectorAll('[data-testid="stSidebar"] [data-testid="stSelectbox"] input[role="combobox"]');
                    inputs.forEach(function(input){
                        input.setAttribute('readonly', '');
                        input.setAttribute('tabindex', '-1');
                        input.setAttribute('inputmode', 'none');
                    });
                } catch (e) {}
            }
            lock();
            setTimeout(lock, 200);
            setTimeout(lock, 800);
            setInterval(lock, 1500);
        })();
        </script>
        """,
        height=0,
    )
    if st.session_state.lang_selector != st.session_state.selected_language:
        st.session_state.selected_language = st.session_state.lang_selector
        st.rerun()

    # Footer: Privacy & Terms + copyright.
    # The Privacy link was an <a href="?mode=privacy"> anchor which
    # triggered a full page reload - that reload dropped the session
    # token and logged the user out. Now a Streamlit button (in-app
    # rerun, no reload) - styled to look exactly like the original link.
    # Render the button first, then the copyright as a separate
